(function() {
// ═══════════════════════════════════════════
// EINHEITEN-BIBLIOTHEK (shared, localStorage)
// ═══════════════════════════════════════════
const DEFAULT_UNITS = [
  { id: 'kps',     label: 'Kps.',    presets: [0.5, 1, 2, 3]          },
  { id: 'mg',      label: 'mg',      presets: [50, 100, 200, 400, 500, 1000] },
  { id: 'g',       label: 'g',       presets: [1, 2, 3, 5, 10]        },
  { id: 'ml',      label: 'ml',      presets: [2.5, 5, 10, 15, 20]    },
  { id: 'tropfen', label: 'Tropfen', presets: [1, 2, 3, 5, 10]        },
  { id: 'huebe',   label: 'Hübe',    presets: [1, 2, 3]               },
  { id: 'stk',     label: 'Stk',     presets: [0.5, 1, 2]             },
  { id: 'tbl',     label: 'Tbl.',    presets: [0.5, 1, 2, 3]          },
  { id: 'ie',      label: 'IE',      presets: [1000, 2000, 5000, 10000] },
];

function loadUnits() { return DEFAULT_UNITS.slice(); }
function saveUnits(u) { /* in-memory */ }
function getPresetsForUnit(unitLabel) {
  return loadUnits().find(u => u.label === unitLabel)?.presets || [1, 2, 3];
}
function populateUnitSelects() {
  const units = loadUnits();
  const opts = units.map(u => `<option value="${u.label}">${u.label}</option>`).join('');
  document.querySelectorAll('select.unit-select').forEach(sel => {
    const prev = sel.value;
    sel.innerHTML = opts;
    if ([...sel.options].some(o => o.value === prev)) sel.value = prev;
  });
}
function openUnitsLib() {
  renderUnitsLibChips();
  document.getElementById('med-new-unit-input').value = '';
  openModal('med-modal-units-lib');
}
function renderUnitsLibChips() {
  const units = loadUnits();
  document.getElementById('med-units-lib-chips').innerHTML = units.map(u =>
    `<span style="display:inline-flex;align-items:center;gap:4px;background:var(--surface2);border:1px solid var(--border);border-radius:20px;padding:5px 10px;font-family:'JetBrains Mono',monospace;font-size:11px;color:var(--text)">
      ${u.label}
      ${!u.builtin ? `<button onclick="window.med_deleteUnit('${u.id}')" style="background:none;border:none;color:var(--muted);font-size:12px;cursor:pointer;padding:0;line-height:1;margin-left:2px">×</button>` : ''}
    </span>`
  ).join('');
}
function addUnit() {
  const input = document.getElementById('med-new-unit-input');
  const label = input.value.trim();
  if (!label) return;
  const units = loadUnits();
  if (units.find(u => u.label.toLowerCase() === label.toLowerCase())) {
    showToast('Einheit bereits vorhanden'); return;
  }
  units.push({ id: 'custom_' + Date.now(), label, presets: [1, 2, 3, 5] });
  units.sort((a, b) => a.label.localeCompare(b.label, 'de'));
  saveUnits(units);
  input.value = '';
  renderUnitsLibChips();
  showToast(`"${label}" hinzugefügt`);
}
function deleteUnit(unitId) {
  saveUnits(loadUnits().filter(u => u.id !== unitId));
  renderUnitsLibChips();
}

// ═══════════════════════════════════════════
// STATE
// ═══════════════════════════════════════════

// Persisted med list: [{id, name, unit, defaultDose}]
let medList = [
  { id: 'med-ibu',  name: 'Ibuprofen',     unit: 'mg',   defaultDose: 400,  stacks: [] },
  { id: 'med-levo', name: 'Levocetirizin', unit: 'Kps.', defaultDose: 1,    stacks: [] },
  { id: 'med-nasa', name: 'Nasenspray',    unit: 'Hübe', defaultDose: 2,    stacks: [], subOptions: ['Links', 'Rechts', 'Beide'] },
] || [
  { id: 'levo',  name: 'Levocetirizin', unit: 'mg',   defaultDose: 5,   intervalDays: null, lastUsed: null },
  { id: 'ibup',  name: 'Ibuprofen',     unit: 'mg',   defaultDose: 400, intervalDays: null, lastUsed: null },
  { id: 'nasen', name: 'Nasenspray',    unit: 'Hübe', defaultDose: 2,   intervalDays: null, lastUsed: null },
];

// Session entries: [{id, medId, name, dose, unit, time}]
let medEntries = [];

// Delete mode
let deleteMode = false;

// Context for take-modal
let takeCtx = null; // {med}

function saveMedList() {
  // (in-memory)
}

function sortMedList() {
  medList.sort((a, b) => a.name.localeCompare(b.name, 'de'));
}

function nowTime() {
  const n = new Date();
  return `${String(n.getHours()).padStart(2,'0')}:${String(n.getMinutes()).padStart(2,'0')}`;
}

function uid() {
  return Math.random().toString(36).slice(2, 9);
}

// ═══════════════════════════════════════════
// RENDER
// ═══════════════════════════════════════════

function render() {
  renderMedListChips();
  renderMedEntryChips();
}

function renderMedListChips() {
  const el = document.getElementById('med-list-chips');
  const chips = medList.map(med => {
    const doseStr = med.defaultDose ? `${med.defaultDose}${med.unit}` : med.unit;
    const ivs = intervalStatusMed(med);
    if (deleteMode) {
      return `<div class="chip chip-med-list" style="border-color:var(--delete-color);flex-direction:row;align-items:center;justify-content:space-between;gap:6px">
        <div style="flex:1;display:flex;align-items:center;gap:5px">💊 ${med.name} <span class="chip-dose">${doseStr}</span></div>
        <div style="display:flex;gap:4px;flex-shrink:0">
          <button class="chip-edit-btn" onclick="window.med_openEditMed('${med.id}')">✎</button>
          <button class="chip-del-btn" onclick="window.med_deleteMed('${med.id}')">✕</button>
        </div>
      </div>`;
    }
    return `<button class="chip chip-med-list${ivs&&!ivs.due?' not-due':''}"
      data-medid="${med.id}"
      onclick="window.med_quickTake('${med.id}')"
      style="flex-direction:column;align-items:flex-start;padding:6px 11px">
      <div style="display:flex;align-items:center;gap:5px">
        💊 ${med.name} <span class="chip-dose">${doseStr}</span>
        <span class="chip-hint">⋯</span>
      </div>
      ${ivs ? `<div style="font-size:9px;color:${ivs.due?'var(--accent2)':'var(--muted)'};margin-top:2px">${ivs.label}</div>` : ''}
    </button>`;
  }).join('');

  const addBtn = deleteMode ? '' :
    `<button class="chip chip-add" onclick="window.med_openNewMed()" title="Medikament hinzufügen">+</button>`;

  el.innerHTML = chips + addBtn;
}

function renderMedEntryChips() {
  const el = document.getElementById('med-entry-chips');
  const empty = document.getElementById('med-empty');

  if (!medEntries.length) {
    el.innerHTML = '<div class="empty-state">Noch keine Einnahmen</div>';
    return;
  }

  // Sort entries by time
  const sorted = [...medEntries].sort((a, b) => a.time.localeCompare(b.time));

  el.innerHTML = sorted.map(entry => {
    const doseStr = entry.dose ? `${entry.dose}${entry.unit}` : '';
    if (deleteMode) {
      return `<div class="chip chip-entry" style="border-color:var(--delete-color);flex-direction:row;align-items:center;justify-content:space-between;gap:6px">
        <div style="flex:1;display:flex;align-items:center;gap:5px">
          ${entry.name}
          ${doseStr ? `<span class="chip-dose-val">${doseStr}</span>` : ''}
          <span class="chip-time">${entry.time}</span>${entry.subOption ? ` <span style="font-size:9px;color:var(--muted)">${entry.subOption}</span>` : ''}${entry.comment ? ` <span style="font-size:11px" title="${entry.comment}">💬</span>` : ''}
        </div>
        <button class="chip-del-btn" onclick="window.med_deleteEntry('${entry.id}')">✕</button>
      </div>`;
    }
    return `<button class="chip chip-entry"
      data-entryid="${entry.id}">
      ${entry.name}
      ${doseStr ? `<span class="chip-dose-val">${doseStr}</span>` : ''}
      <span class="chip-time">${entry.time}</span>
      ${entry.comment ? `<span style="font-size:11px" title="${entry.comment}">💬</span>` : ''}
      <span class="chip-hint">⋯</span>
    </button>`;
  }).join('');
}

// ═══════════════════════════════════════════
// DELETE MODE
// ═══════════════════════════════════════════

function toggleDeleteMode() {
  deleteMode = !deleteMode;
  const btn = document.getElementById('med-delete-mode-btn');
  btn.classList.toggle('active', deleteMode);
  btn.textContent = deleteMode ? '✓ Fertig' : '🗑 Löschen';
  render();
}

function deleteMed(id) {
  const med = medList.find(m => m.id === id);
  medList = medList.filter(m => m.id !== id);
  saveMedList();
  render();
  showToast(`${med?.name} entfernt`);
  // Auto-exit delete mode if list empty
  if (!medList.length) toggleDeleteMode();
}

function deleteEntry(id) {
  const entry = medEntries.find(e => e.id === id);
  medEntries = medEntries.filter(e => e.id !== id);
  render();
  showToast(`Einnahme ${entry?.name} gelöscht`);
}

// ═══════════════════════════════════════════
// NEW MED MODAL
// ═══════════════════════════════════════════



function renderSubOptions(med) {
  var container = document.getElementById('med-take-sub-options');
  if (!container) return;
  if (!med || !med.subOptions || !med.subOptions.length) {
    container.style.display = 'none';
    window._medSubOption = '';
    return;
  }
  container.style.display = 'block';
  var saved = (takeCtx && takeCtx.editId)
    ? ((medEntries.find(function(e){ return e.id===takeCtx.editId; })||{}).subOption || '')
    : '';
  window._medSubOption = saved;
  var btns = med.subOptions.map(function(opt) {
    var sel = saved===opt ? ' selected' : '';
    return '<button class="dose-btn sub-opt-btn' + sel + '" onclick="window.med_pickSubOpt(this,\'' + opt + '\')" style="flex:1">' + opt + '</button>';
  }).join('');
  container.innerHTML = '<label class="modal-field-label">Seite</label><div style="display:flex;gap:6px;margin-bottom:12px">' + btns + '</div>';
}

function pickSubOpt(btn, opt) {
  btn.closest('div').querySelectorAll('.sub-opt-btn').forEach(function(b){ b.classList.remove('selected'); });
  btn.classList.add('selected');
  window._medSubOption = opt;
}

function openNewMed() {
  populateUnitSelects();
  document.getElementById('med-new-med-name').value = '';
  document.getElementById('med-new-med-dose').value = '';
  document.getElementById('med-new-med-unit').value = 'mg';
  updateDoseQuick();
  openModal('med-modal-new-med');
  setTimeout(() => document.getElementById('med-new-med-name').focus(), 100);
}

function updateDoseQuick() {
  const unit = document.getElementById('med-new-med-unit').value;
  const presets = getPresetsForUnit(unit);
  const currentVal = document.getElementById('med-new-med-dose').value;

  document.getElementById('med-new-med-dose-quick').innerHTML = presets.map(v =>
    `<button class="dose-btn${parseFloat(currentVal) === v ? ' selected' : ''}"
      onclick="window.med_selectDosePreset('med-new-med-dose', ${v}, this)">${v}</button>`
  ).join('');
}

function selectDosePreset(inputId, val, btn) {
  document.getElementById(inputId).value = val;
  // Highlight selected
  btn.closest('.dose-quick').querySelectorAll('.dose-btn').forEach(b => b.classList.remove('selected'));
  btn.classList.add('selected');
}

function saveMed() {
  const name = document.getElementById('med-new-med-name').value.trim();
  const unit = document.getElementById('med-new-med-unit').value;
  const dose = parseFloat(document.getElementById('med-new-med-dose').value) || null;

  if (!name) { showToast('Bitte Namen eingeben'); return; }
  if (medList.find(m => m.name.toLowerCase() === name.toLowerCase())) {
    showToast('Medikament bereits vorhanden'); return;
  }

  medList.push({ id: uid(), name, unit, defaultDose: dose });
  sortMedList();
  saveMedList();
  closeModal('med-modal-new-med');
  render();
  showToast(`${name} hinzugefügt`);
}

// ═══════════════════════════════════════════
// TAKE MED MODAL
// ═══════════════════════════════════════════

// ── QUICK TAKE (kurzer Tap auf Listen-Chip) ──
function quickTake(medId) {
  const med = medList.find(m => m.id === medId);
  if (!med) return;
  const now = new Date();
  const t = String(now.getHours()).padStart(2,'0') + ':' + String(now.getMinutes()).padStart(2,'0');
  medEntries.push({ id: uid(), medId: med.id, name: med.name, dose: med.defaultDose, unit: med.unit, time: t, comment: '' });
  render();
  const doseStr = med.defaultDose ? ` · ${med.defaultDose}${med.unit}` : '';
  showToast(`${med.name}${doseStr} um ${t} ✓`);
}

function openTake(medId) {
  populateUnitSelects();
  const med = medList.find(m => m.id === medId);
  if (!med) return;
  takeCtx = { med };
  document.getElementById('med-take-med-title').textContent = `💊 ${med.name}`;
  document.getElementById('med-take-time-input').value = nowTime();
  document.getElementById('med-take-dose-input').value = med.defaultDose || '';
  // Set unit select
  populateUnitSelects();
  document.getElementById('med-take-unit-input').value = med.unit;
  updateTakeDoseQuick();
  var _cEl=document.getElementById('med-take-comment'); if(_cEl) _cEl.value = takeCtx.editId ? (medEntries.find(function(e){return e.id===takeCtx.editId;})||{}).comment||'' : '';
  openModal('med-modal-take-med');
}

function updateTakeDoseQuick() {
  const unit = document.getElementById('med-take-unit-input').value;
  const curVal = document.getElementById('med-take-dose-input').value;
  const presets = getPresetsForUnit(unit);
  document.getElementById('med-take-dose-quick').innerHTML = presets.map(v =>
    `<button class="dose-btn${parseFloat(curVal) === v ? ' selected' : ''}"
      onclick="window.med_selectDosePreset('med-take-dose-input', ${v}, this)">${v}</button>`
  ).join('');
}

function confirmTake() {
  if (!takeCtx) return;
  const dose = parseFloat(document.getElementById('med-take-dose-input').value) || null;
  const unit = document.getElementById('med-take-unit-input').value;
  const time = document.getElementById('med-take-time-input').value || nowTime();
  const commentEl = document.getElementById('med-take-comment');
  const comment = commentEl ? commentEl.value.trim() : '';

  if (takeCtx.editId) {
    const idx = medEntries.findIndex(e => e.id === takeCtx.editId);
    if (idx !== -1) {
      medEntries[idx].dose = dose;
      medEntries[idx].unit = unit;
      medEntries[idx].time = time;
      medEntries[idx].comment = comment;
      medEntries[idx].subOption = window._medSubOption || medEntries[idx].subOption || '';
    }
    closeModal('med-modal-take-med');
    takeCtx = null;
    render();
    showToast('Einnahme aktualisiert ✓');
  } else {
    const { med } = takeCtx;
    medEntries.push({ id: uid(), medId: med.id, name: med.name, dose, comment: comment || '', unit, time, subOption: window._medSubOption || '' });
    closeModal('med-modal-take-med');
    takeCtx = null;
    render();
    const doseStr = dose ? ` · ${dose}${unit}` : '';
    showToast(`${med.name}${doseStr} um ${time} ✓`);
  }
}

// ── EDIT ENTRY (langer Tap auf Einnahme-Chip) ──
function editEntry(entryId) {
  const entry = medEntries.find(e => e.id === entryId);
  if (!entry) return;
  const med = medList.find(m => m.id === entry.medId) || { name: entry.name, unit: entry.unit, defaultDose: entry.dose };
  takeCtx = { med, editId: entryId };
  document.getElementById('med-take-med-title').textContent = `✎ ${entry.name} bearbeiten`;
  document.getElementById('med-take-time-input').value = entry.time;
  document.getElementById('med-take-dose-input').value = entry.dose || '';
  populateUnitSelects();
  document.getElementById('med-take-unit-input').value = entry.unit;
  renderSubOptions(med);
  updateTakeDoseQuick();
  var _cEl=document.getElementById('med-take-comment'); if(_cEl) _cEl.value = takeCtx.editId ? (medEntries.find(function(e){return e.id===takeCtx.editId;})||{}).comment||'' : '';
  openModal('med-modal-take-med');
}

// ── LONG PRESS ────────────────────────────
let lpTimer = null, lpFired = false;

document.addEventListener('click', e => {
  if (lpFired) { lpFired = false; e.stopImmediatePropagation(); e.preventDefault(); }
}, true);

// ═══════════════════════════════════════════
// MODAL HELPERS
// ═══════════════════════════════════════════

function openModal(id) {
  document.getElementById(id).classList.add('open');
}
function closeModal(id) {
  document.getElementById(id).classList.remove('open');
  takeCtx = null;
}
// Close on overlay click

// ═══════════════════════════════════════════
// TOAST
// ═══════════════════════════════════════════

let toastTimer;
function showToast(msg) {
  const el = document.getElementById('toast');
  el.textContent = msg;
  el.classList.add('show');
  clearTimeout(toastTimer);
  toastTimer = setTimeout(() => el.classList.remove('show'), 2200);
}

// ── DATUM / INTERVALL ────────────────────
let simDate = null;
function today(){ return simDate || new Date().toISOString().slice(0,10); }

function intervalStatusMed(med){
  if(!med.intervalDays) return null;
  if(!med.lastUsed) return { due:true, label:'noch nie → heute fällig' };
  const diff = Math.round((new Date(today()) - new Date(med.lastUsed)) / (1000*60*60*24));
  const rem = med.intervalDays - diff;
  if(rem <= 0) return { due:true,  label:`zuletzt vor ${diff}d → heute fällig` };
  if(rem === 1) return { due:false, label:`zuletzt vor ${diff}d → morgen fällig` };
  return { due:false, label:`zuletzt vor ${diff}d → in ${rem}d fällig` };
}

// ── EDIT MED ─────────────────────────────
let editMedCtx = null;

function openEditMed(medId){
  const med = medList.find(m => m.id === medId);
  if(!med) return;
  editMedCtx = { medId };
  document.getElementById('med-edit-med-name').value = med.name;
  document.getElementById('med-edit-med-dose').value = med.defaultDose || '';
  const hasInterval = !!med.intervalDays;
  document.getElementById('med-edit-med-interval-on').checked = hasInterval;
  document.getElementById('med-edit-med-interval-days').disabled = !hasInterval;
  document.getElementById('med-edit-med-interval-days').value = med.intervalDays || 2;
  populateUnitSelects();
  document.getElementById('med-edit-med-unit').value = med.unit;
  updateEditMedQuick();
  openModal('med-modal-edit-med');
  setTimeout(()=>document.getElementById('med-edit-med-name').focus(), 100);
}

function updateEditMedQuick(){
  const unit = document.getElementById('med-edit-med-unit').value;
  const cur = parseFloat(document.getElementById('med-edit-med-dose').value);
  const presets = getPresetsForUnit(unit);
  document.getElementById('med-edit-med-dose-quick').innerHTML = presets.map(v =>
    `<button class="dose-btn${cur===v?' selected':''}"
      onclick="window.med_selectDosePreset('med-edit-med-dose',${v},this)">${v}</button>`
  ).join('');
}

function saveEditMed(){
  if(!editMedCtx) return;
  const med = medList.find(m => m.id === editMedCtx.medId);
  if(!med) return;
  const name = document.getElementById('med-edit-med-name').value.trim();
  const unit = document.getElementById('med-edit-med-unit').value;
  const dose = parseFloat(document.getElementById('med-edit-med-dose').value) || null;
  const intervalOn = document.getElementById('med-edit-med-interval-on').checked;
  const intervalDays = intervalOn ? parseInt(document.getElementById('med-edit-med-interval-days').value) || null : null;
  if(!name){ showToast('Name fehlt'); return; }
  med.name = name; med.unit = unit; med.defaultDose = dose;
  med.intervalDays = intervalDays;
  sortMedList();
  editMedCtx = null;
  closeModal('med-modal-edit-med');
  showToast(`${name} gespeichert ✓`);
  render();
}

// ── KOMMENTARE ─────────────────────────────────────────────

let medComment = '';
let medCommentOpen = false;

function escHtml(s){ return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

function toggleMedComment(){
  medCommentOpen = !medCommentOpen;
  const area = document.getElementById('med-comment-area');
  const preview = document.getElementById('med-comment-preview');
  const btn = document.getElementById('med-comment-btn');
  if(medCommentOpen){
    area.style.display = 'block';
    preview.style.display = 'none';
    document.getElementById('med-comment-text').value = medComment;
    setTimeout(()=>{
      const ta = document.getElementById('med-comment-text');
      if(ta){ ta.focus(); ta.setSelectionRange(ta.value.length, ta.value.length); }
    }, 50);
  } else {
    area.style.display = 'none';
    if(medComment){
      preview.textContent = medComment;
      preview.style.display = 'block';
    } else {
      preview.style.display = 'none';
    }
  }
  btn.classList.toggle('has-comment', !!medComment);
}

function saveMedComment(){
  const val = document.getElementById('med-comment-text').value.trim();
  medComment = val;
  medCommentOpen = false;
  const area = document.getElementById('med-comment-area');
  const preview = document.getElementById('med-comment-preview');
  const btn = document.getElementById('med-comment-btn');
  area.style.display = 'none';
  btn.classList.toggle('has-comment', !!medComment);
  if(medComment){
    preview.textContent = medComment;
    preview.style.display = 'block';
    showToast('Kommentar gespeichert ✓');
  } else {
    preview.style.display = 'none';
    showToast('Kommentar entfernt');
  }
}

// ═══════════════════════════════════════════
// INIT
// ═══════════════════════════════════════════

// Exports
window.med_lpAction=function(el){if(typeof openEditMed==='function')openEditMed(el.dataset.medid);};
window.med_lpEntryAction=function(el){if(typeof editEntry==='function')editEntry(el.dataset.entryid);};
  window.med_deleteEntry = deleteEntry;
  window.med_deleteMed = deleteMed;
  window.med_deleteUnit = deleteUnit;
  window.med_openEditMed = openEditMed;
  window.med_openNewMed = openNewMed;
  window.med_pickSubOpt = pickSubOpt;
  window.med_quickTake = quickTake;
  window.med_selectDosePreset = selectDosePreset;
  window.med_addUnit = addUnit;
  window.med_confirmTake = confirmTake;
  window.med_openUnitsLib = openUnitsLib;
  window.med_populateUnitSelects = populateUnitSelects;
  window.med_render = render;
  window.med_saveEditMed = saveEditMed;
  window.med_saveMed = saveMed;
  window.med_saveMedComment = saveMedComment;
  window.med_toggleDeleteMode = toggleDeleteMode;
  window.med_toggleMedComment = toggleMedComment;
  window.med_updateDoseQuick = updateDoseQuick;
  window.med_updateEditMedQuick = updateEditMedQuick;
  window.med_updateTakeDoseQuick = updateTakeDoseQuick;
  window.med_render = render;
})();

