(function() {
// ── EINHEITEN PRESETS ─────────────────────
const PRESETS = {
  'Kps.':[0.5,1,2,3],'mg':[50,100,200,400,500,1000],
  'g':[1,2,3,5,10],'ml':[2.5,5,10,20],
  'Tropfen':[1,2,3,5,10],'Hübe':[1,2,3],'Stk':[0.5,1,2]
};

const STACKS = [
  {id:'morgen',label:'🌅 Morgen'},
  {id:'mittag',label:'☀️ Mittag'},
  {id:'abend', label:'🌆 Abend'},
  {id:'schlaf',label:'🌙 Schlaf'},
];

// ── STATE (in-memory only) ─────────────────
let suppList = [
  {id:'coq10', name:'CoQ10',              unit:'Kps.',    dose:1, stacks:['morgen']},
  {id:'d3k2',  name:'D3+K2',              unit:'Tropfen', dose:1, stacks:['morgen']},
  {id:'glycin',name:'Glycin',             unit:'g',       dose:5, stacks:['schlaf']},
  {id:'mag',   name:'Magnesium Komplex',  unit:'Kps.',    dose:1, stacks:['abend']},
  {id:'omega3',name:'Omega-3 Complete',   unit:'Kps.',    dose:1, stacks:['morgen']},
  {id:'querc', name:'Quercetin Liposomal',unit:'Kps.',    dose:1, stacks:['morgen']},
  {id:'vitc',  name:'Vitamin-C Komplex',  unit:'Kps.',    dose:1, stacks:['morgen']},
];
suppList.sort((a,b)=>a.name.localeCompare(b.name,'de'));

// takenMap: { 'suppId__stackId': { taken:bool, overrideDose:number|null } }
let takenMap = {};
let delMode = false;
let openStacks = {morgen:true,mittag:false,abend:false,schlaf:false};

// comments: { stackId: string }
let comments = {};
// which stacks have comment area open
let commentOpen = {};
let doseCtx = null;
let lpTimer = null, lpFired = false;

function uid(){return Math.random().toString(36).slice(2,9)}
function isTaken(sid,stk){return takenMap[sid+'__'+stk]?.taken===true}
function getODose(sid,stk){return takenMap[sid+'__'+stk]?.overrideDose??null}
function setTaken(sid,stk,val,od=null){
  const k=sid+'__'+stk;
  if(!val){
    if(takenMap[k]) takenMap[k].taken=false;
    return;
  }
  const existingOd=takenMap[k]?.overrideDose??null;
  takenMap[k]={taken:true,overrideDose:od!==null?od:existingOd};
}
function stackSupps(stk){return suppList.filter(s=>s.stacks.includes(stk))}
function takenCount(stk){return stackSupps(stk).filter(s=>isTaken(s.id,stk)).length}

// ── RENDER ────────────────────────────────
function render(){
  document.getElementById('supp-stacks').innerHTML=STACKS.map(renderStack).join('');
}

function renderStack(stk){
  const supps=stackSupps(stk.id);
  const tc=takenCount(stk.id), total=supps.length;
  const isOpen=openStacks[stk.id];
  let bc='',bt='—';
  if(total>0){
    if(tc===total){bc='ok';bt=`✓ ${tc}/${total}`}
    else if(tc>0){bc='partial';bt=`${tc}/${total}`}
    else{bt=`0/${total}`}
  }
  const allTaken=total>0&&tc===total;
  const chips=supps.map(s=>{
    const taken=isTaken(s.id,stk.id);
    const od=getODose(s.id,stk.id);
    const d=od!==null?od:s.dose;
    const ds=d?`${d}${s.unit}`:s.unit;
    const changed=od!==null&&od!==s.dose;
    if(delMode) return `<div class="chip del" style="flex-direction:row;align-items:center;justify-content:space-between;gap:6px">
      <div style="flex:1;display:flex;align-items:center;gap:5px">${s.name} <span class="chip-dose">${ds}</span></div>
      <div style="display:flex;gap:4px;flex-shrink:0">
        <button class="chip-edit-btn" onclick="window.supp_openEdit('${s.id}')">✎</button>
        <button class="chip-del-btn" onclick="window.supp_delSupp('${s.id}','${stk.id}')">✕</button>
      </div>
    </div>`;
    return `<button class="chip${taken?' taken':''}${changed?' dose-changed':''}"
      data-sid="${s.id}" data-stk="${stk.id}"
      onclick="window.supp_tapChip('${s.id}','${stk.id}')">
      ${taken?'<span class="ck">✓</span>':''} ${s.name} <span class="chip-dose">${ds}</span>${taken?'<span class="chip-hint">⋯</span>':''}${changed?'<span style="color:var(--accent);font-size:9px"> ✎</span>':''}
    </button>`;
  }).join('');
  const addBtn=delMode?'':`<button class="chip chip-add" onclick="window.supp_openNew('${stk.id}')">+</button>`;
  const hasComment=!!(comments[stk.id]&&comments[stk.id].trim());
  const commentIsOpen=!!commentOpen[stk.id];
  return `<div class="stack-card">
    <div class="stack-header" onclick="window.supp_toggleStk('${stk.id}')">
      <span class="stack-label">${stk.label}</span>
      <span style="display:flex;align-items:center;gap:6px">
        <span class="stack-badge ${bc}">${bt}</span>
        <button class="comment-btn${hasComment?' has-comment':''}"
          onclick="event.stopPropagation();window.supp_toggleComment('${stk.id}')"
          title="${hasComment?'Kommentar bearbeiten':'Kommentar hinzufügen'}">💬</button>
        <span style="color:var(--muted);font-size:12px">${isOpen?'▲':'▼'}</span>
      </span>
    </div>
    ${isOpen?`<div class="stack-body">
      ${total>0?`<button class="btn-alle${allTaken?' all-taken':''}" onclick="window.supp_toggleAll('${stk.id}')">${allTaken?'✓ Alle genommen':'◎ Alle markieren'}</button>`:''}
      <div class="chip-row">${chips}${addBtn}</div>
      ${commentIsOpen?`
      <div class="comment-area">
        <textarea class="comment-textarea" id="comment-${stk.id}"
          placeholder="Kommentar zum ${stk.label}-Stack..."
          oninput="previewComment('${stk.id}')"
        >${comments[stk.id]||''}</textarea>
        <div class="comment-actions">
          <button class="comment-clear" onclick="window.supp_clearComment('${stk.id}')">Leeren</button>
          <button class="comment-save" onclick="window.supp_saveComment('${stk.id}')">Speichern</button>
        </div>
      </div>`:
      hasComment?`<div class="comment-preview" onclick="window.supp_toggleComment('${stk.id}')">${escHtml(comments[stk.id])}</div>`:''}
    </div>`:''}
  </div>`;
}

function toggleStk(id){openStacks[id]=!openStacks[id];render()}

// ── COMMENTS ─────────────────────────────
function escHtml(s){return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}

function toggleComment(stackId){
  commentOpen[stackId]=!commentOpen[stackId];
  // Make sure stack is open
  if(commentOpen[stackId]) openStacks[stackId]=true;
  render();
  if(commentOpen[stackId]){
    setTimeout(()=>{
      const ta=document.getElementById('comment-'+stackId);
      if(ta){ta.focus();ta.setSelectionRange(ta.value.length,ta.value.length)}
    },50);
  }
}

function saveComment(stackId){
  const ta=document.getElementById('comment-'+stackId);
  const val=ta?ta.value.trim():'';
  if(val){
    comments[stackId]=val;
    showToast('Kommentar gespeichert ✓');
  } else {
    delete comments[stackId];
    showToast('Kommentar entfernt');
  }
  commentOpen[stackId]=false;
  render();
}

function clearComment(stackId){
  const ta=document.getElementById('comment-'+stackId);
  if(ta) ta.value='';
}

function previewComment(stackId){
  // live — nothing needed, textarea handles itself
}

// ── TAP + LONG PRESS ──────────────────────
function tapChip(sid,stk){
  // short tap: toggle taken
  const cur=isTaken(sid,stk);
  if(cur){
    setTaken(sid,stk,false);
    render();
  } else {
    setTaken(sid,stk,true,null);
    const s=suppList.find(x=>x.id===sid);
    showToast(`${s?.name} ✓`);
    render();
  }
}

// Long press setup
document.addEventListener('click',e=>{
  if(lpFired){lpFired=false;e.stopImmediatePropagation();e.preventDefault();}
},true);

// ── ALLE ──────────────────────────────────
function toggleAll(stk){
  const supps=stackSupps(stk);
  const all=supps.every(s=>isTaken(s.id,stk));
  supps.forEach(s=>setTaken(s.id,stk,!all,null));
  showToast(all?'Alle abgewählt':`Alle ${supps.length} ✓`);
  render();
}

// ── DELETE MODE ───────────────────────────
function toggleDelMode(){
  delMode=!delMode;
  const btn=document.getElementById('supp-btn-del');
  btn.classList.toggle('on',delMode);
  btn.textContent=delMode?'✓ Fertig':'🗑 Löschen';
  if(delMode)STACKS.forEach(s=>openStacks[s.id]=true);
  render();
}
function delSupp(sid,stk){
  const s=suppList.find(x=>x.id===sid);
  if(!s)return;
  s.stacks=s.stacks.filter(x=>x!==stk);
  if(!s.stacks.length){suppList=suppList.filter(x=>x.id!==sid);showToast(`${s.name} entfernt`)}
  else showToast(`${s.name} aus Stack entfernt`);
  render();
}

// ── DOSE MODAL ────────────────────────────
function openDoseModal(sid,stk){
  const s=suppList.find(x=>x.id===sid);
  if(!s)return;
  doseCtx={sid,stk,s};
  document.getElementById('supp-m-dose-title').textContent=`✎ ${s.name} — Dosis heute`;
  const cur=getODose(sid,stk)??s.dose;
  document.getElementById('supp-m-dose-val').value=cur||'';
  const ps=PRESETS[s.unit]||[];
  document.getElementById('supp-m-dose-quick').innerHTML=ps.map(v=>
    `<button class="db${parseFloat(cur)===v?' sel':''}" onclick="window.supp_pickDose(${v},this)">${v}${s.unit}</button>`
  ).join('');
  openModal('supp-m-dose');
}
function pickDose(v,btn){
  document.getElementById('supp-m-dose-val').value=v;
  btn.closest('.dq').querySelectorAll('.db').forEach(b=>b.classList.remove('sel'));
  btn.classList.add('sel');
}
function confirmDose(){
  if(!doseCtx)return;
  const {sid,stk,s}=doseCtx;
  const d=parseFloat(document.getElementById('supp-m-dose-val').value)||null;
  if(d!=null) doseMemory[sid+'__'+stk]=d;
  setTaken(sid,stk,true,d);
  closeModal('supp-m-dose');doseCtx=null;
  showToast(`${s.name}${d?` · ${d}${s.unit}`:''} ✓`);
  render();
}
function cancelDose(){
  if(!doseCtx)return;
  const {sid,stk,s}=doseCtx;
  setTaken(sid,stk,false);
  closeModal('supp-m-dose');doseCtx=null;
  showToast(`${s.name} abgewählt`);
  render();
}

// ── NEW SUPP MODAL ────────────────────────
function openNew(preStk){
  document.getElementById('supp-m-new-name').value='';
  document.getElementById('supp-m-new-dose').value='';
  document.getElementById('supp-m-new-unit').value='Kps.';
  document.querySelectorAll('#supp-m-new-stacks .stk-btn').forEach(b=>
    b.classList.toggle('sel',b.dataset.s===preStk));
  updateNewQuick();
  openModal('supp-m-new');
  setTimeout(()=>document.getElementById('supp-m-new-name').focus(),100);
}
function updateNewQuick(){
  const u=document.getElementById('supp-m-new-unit').value;
  const cur=parseFloat(document.getElementById('supp-m-new-dose').value);
  document.getElementById('supp-m-new-quick').innerHTML=(PRESETS[u]||[]).map(v=>
    `<button class="db${cur===v?' sel':''}" onclick="window.supp_pickNew(${v},this)">${v}${u}</button>`
  ).join('');
}
function pickNew(v,btn){
  document.getElementById('supp-m-new-dose').value=v;
  btn.closest('.dq').querySelectorAll('.db').forEach(b=>b.classList.remove('sel'));
  btn.classList.add('sel');
}
function saveNew(){
  const name=document.getElementById('supp-m-new-name').value.trim();
  const unit=document.getElementById('supp-m-new-unit').value;
  const dose=parseFloat(document.getElementById('supp-m-new-dose').value)||null;
  const stacks=[...document.querySelectorAll('#supp-m-new-stacks .stk-btn.sel')].map(b=>b.dataset.s);
  if(!name){showToast('Name fehlt');return}
  if(!stacks.length){showToast('Stack wählen');return}
  const ex=suppList.find(s=>s.name.toLowerCase()===name.toLowerCase());
  if(ex){stacks.forEach(st=>{if(!ex.stacks.includes(st))ex.stacks.push(st)});showToast(`${name} aktualisiert`)}
  else{suppList.push({id:uid(),name,unit,dose,stacks});suppList.sort((a,b)=>a.name.localeCompare(b.name,'de'));showToast(`${name} hinzugefügt`)}
  closeModal('supp-m-new');render();
}

// ── EDIT ─────────────────────────────────
let editCtx=null;
function openEdit(sid){
  const s=suppList.find(x=>x.id===sid);
  if(!s)return;
  editCtx={sid};
  document.getElementById('supp-m-edit-name').value=s.name;
  document.getElementById('supp-m-edit-unit').value=s.unit||'Kps.';
  document.getElementById('supp-m-edit-dose').value=s.dose||'';
  document.querySelectorAll('#supp-m-edit-stacks .stk-btn').forEach(b=>
    b.classList.toggle('sel',s.stacks.includes(b.dataset.s)));
  updateEditQuick();
  openModal('supp-m-edit');
  setTimeout(()=>document.getElementById('supp-m-edit-name').focus(),100);
}
function updateEditQuick(){
  const u=document.getElementById('supp-m-edit-unit').value;
  const cur=parseFloat(document.getElementById('supp-m-edit-dose').value);
  document.getElementById('supp-m-edit-quick').innerHTML=(PRESETS[u]||[]).map(v=>
    `<button class="db${cur===v?' sel':''}" onclick="window.supp_pickEdit(${v},this)">${v}${u}</button>`
  ).join('');
}
function pickEdit(v,btn){
  document.getElementById('supp-m-edit-dose').value=v;
  btn.closest('.dq').querySelectorAll('.db').forEach(b=>b.classList.remove('sel'));
  btn.classList.add('sel');
}
function saveEdit(){
  if(!editCtx)return;
  const s=suppList.find(x=>x.id===editCtx.sid);
  if(!s)return;
  const name=document.getElementById('supp-m-edit-name').value.trim();
  const unit=document.getElementById('supp-m-edit-unit').value;
  const dose=parseFloat(document.getElementById('supp-m-edit-dose').value)||null;
  const stacks=[...document.querySelectorAll('#supp-m-edit-stacks .stk-btn.sel')].map(b=>b.dataset.s);
  if(!name){showToast('Name fehlt');return}
  if(!stacks.length){showToast('Stack wählen');return}
  s.name=name;s.unit=unit;s.dose=dose;s.stacks=stacks;
  suppList.sort((a,b)=>a.name.localeCompare(b.name,'de'));
  editCtx=null;
  closeModal('supp-m-edit');
  showToast(`${name} gespeichert ✓`);
  render();
}

// ── MODALS ────────────────────────────────
function openModal(id){document.getElementById(id).classList.add('open')}
function closeModal(id){document.getElementById(id).classList.remove('open')}

// ── TOAST ─────────────────────────────────
let tt;
function showToast(msg){
  const el=document.getElementById('toast');
  el.textContent=msg;el.classList.add('show');
  clearTimeout(tt);tt=setTimeout(()=>el.classList.remove('show'),2200);
}

// ── INIT ──────────────────────────────────
// Exports
window.supp_lpAction=function(btn){setTimeout(function(){if(window._lpFired!==undefined)window._lpFired=false;},50);if(typeof isTaken==='function'&&!isTaken(btn.dataset.sid,btn.dataset.stk))return;openDoseModal(btn.dataset.sid,btn.dataset.stk);};
  window.supp_clearComment = clearComment;
  window.supp_delSupp = delSupp;
  window.supp_openEdit = openEdit;
  window.supp_openNew = openNew;
  window.supp_pickDose = pickDose;
  window.supp_pickEdit = pickEdit;
  window.supp_pickNew = pickNew;
  window.supp_saveComment = saveComment;
  window.supp_tapChip = tapChip;
  window.supp_toggleAll = toggleAll;
  window.supp_toggleComment = toggleComment;
  window.supp_toggleStk = toggleStk;
  window.supp_cancelDose = cancelDose;
  window.supp_confirmDose = confirmDose;
  window.supp_render = render;
  window.supp_saveEdit = saveEdit;
  window.supp_saveNew = saveNew;
  window.supp_toggleDelMode = toggleDelMode;
  window.supp_updateEditQuick = updateEditQuick;
  window.supp_updateNewQuick = updateNewQuick;
  window.supp_render = render;
})();

