(function() {
// ── PRESETS per unit ──────────────────────
const PRESETS = {
  'Pumps':       [1,2,3,4],
  'Sprühstoß':   [1,2,3],
  'ml':          [1,2,5,10,15,20],
  'Tropfen':     [1,2,3,5],
  'Fingerkuppe': [0.5,1,2],
  'Hübe':        [1,2,3],
  'g':           [1,2,3,5],
  'Stk':         [0.5,1,2],
};

const GROUPS = [
  {id:'morgen', label:'🌅 Morgen-Routine'},
  {id:'abend',  label:'🌆 Abend-Routine'},
];

// ── STATE ─────────────────────────────────
// products: [{id, name, unit, dose, groups:[], intervalDays:null, lastUsed:null}]
// lastUsed: ISO date string 'YYYY-MM-DD' — would be persisted in real app
let products = [
  {id:'ant',  name:'Anthelios 50+',    unit:'Pumps',  dose:2,    groups:['morgen'], intervalDays:null, lastUsed:null},
  {id:'cica', name:'Cicaplast Mains',  unit:'Pumps',  dose:1,    groups:['morgen','abend'], intervalDays:null, lastUsed:null},
  {id:'lip1', name:'Lipikar Baume AP+M',unit:'Pumps', dose:3,    groups:['morgen','abend'], intervalDays:null, lastUsed:null},
  {id:'lip2', name:'Lipikar Syndet AP+',unit:'ml',    dose:10,   groups:['morgen'], intervalDays:null, lastUsed:null},
  {id:'terz', name:'Terzolin 2%',      unit:'ml',     dose:5,    groups:['morgen'], intervalDays:2,    lastUsed:'2025-04-06'},
  {id:'tol',  name:'Toleriane Creme',  unit:'Pumps',  dose:2,    groups:['morgen'], intervalDays:null, lastUsed:null},
  {id:'toln', name:'Toleriane Nuit',   unit:'Pumps',  dose:2,    groups:['abend'],  intervalDays:null, lastUsed:null},
];
products.sort((a,b)=>a.name.localeCompare(b.name,'de'));

// doneMap: { 'prodId__groupId': { done:bool, overrideDose:number|null } }
let doneMap = {};
let delMode = false;
let openGroups = {morgen:true, abend:false};
let comments = {};
let commentOpen = {};
let doseCtx = null;
let lpTimer = null, lpFired = false;

// ── HELPERS ───────────────────────────────
function uid(){return Math.random().toString(36).slice(2,9)}
// ── DATUM-SIMULATOR ──────────────────────
let simDate = null; // null = echter heutiger Tag

function today(){
  if(simDate) return simDate;
  return new Date().toISOString().slice(0,10);
}

function setSimDate(val){
  simDate = val || null;
  render();
  const lbl = document.getElementById('haut-sim-date-label');
  if(lbl) lbl.textContent = simDate ? `Simuliert: ${simDate}` : 'Heute (echt)';
}

function isDone(pid,grp){return !!(doneMap[pid+'__'+grp]?.done)}
function getODose(pid,grp){return doneMap[pid+'__'+grp]?.overrideDose??null}
function setDone(pid,grp,val,od=null){
  const k=pid+'__'+grp;
  if(!val){delete doneMap[k];return}
  doneMap[k]={done:true,overrideDose:od};
}

function groupProds(grp){return products.filter(p=>p.groups.includes(grp))}
function doneCount(grp){return groupProds(grp).filter(p=>isDone(p.id,grp)).length}

// ── INTERVAL LOGIC ────────────────────────
function intervalStatus(prod){
  if(!prod.intervalDays)return null; // no interval
  if(!prod.lastUsed)return {due:true, label:'noch nie verwendet → heute fällig', days:0};
  const last = new Date(prod.lastUsed);
  const now = new Date(today());
  const diff = Math.round((now-last)/(1000*60*60*24));
  const remaining = prod.intervalDays - diff;
  if(remaining<=0) return {due:true,  label:`zuletzt vor ${diff}d → heute fällig`, days:diff};
  if(remaining===1) return {due:false, label:`zuletzt vor ${diff}d → morgen fällig`, days:diff};
  return {due:false, label:`zuletzt vor ${diff}d → in ${remaining}d fällig`, days:diff};
}

// ── RENDER ────────────────────────────────
function render(){
  document.getElementById('haut-stacks').innerHTML=GROUPS.map(renderGroup).join('');
}

function renderGroup(grp){
  const prods=groupProds(grp.id);
  const dc=doneCount(grp.id), total=prods.length;
  const isOpen=openGroups[grp.id];
  let bc='',bt='—';
  if(total>0){
    if(dc===total){bc='ok';bt=`✓ ${dc}/${total}`}
    else if(dc>0){bc='partial';bt=`${dc}/${total}`}
    else bt=`0/${total}`;
  }
  const allDone=total>0&&dc===total;

  const chips=prods.map(p=>{
    const done=isDone(p.id,grp.id);
    const od=getODose(p.id,grp.id);
    const d=od!==null?od:p.dose;
    const ds=p.unit&&d?`${d} ${p.unit}`:'';
    const changed=od!==null&&od!==p.dose;
    const ivs=intervalStatus(p);

    // Interval chip classes
    let chipClass='chip';
    let subText='';
    if(done){
      chipClass+=' done';
      subText=ds?`${ds} angewendet`:'angewendet';
    } else if(ivs){
      chipClass+=ivs.due?' due':' not-due';
      subText=`<span class="${ivs.due?'interval-due':remaining(p)===1?'interval-soon':'interval-wait'}">${ivs.label}</span>`;
    } else {
      subText=ds?`Standard: ${ds}`:'';
    }
    if(changed) chipClass+=' dose-changed';

    if(delMode) return `<div class="chip del-chip" style="flex-direction:row;align-items:center;justify-content:space-between;gap:6px">
      <div class="chip-main" style="flex:1">${p.name}${ds?` <span class="chip-dose">${ds}</span>`:''}</div>
      <div style="display:flex;gap:4px;flex-shrink:0">
        <button class="chip-edit-btn" onclick="window.haut_openEdit('${p.id}')">✎</button>
        <button class="chip-del-btn" onclick="window.haut_delProd('${p.id}','${grp.id}')">✕</button>
      </div>
    </div>`;

    return `<button class="${chipClass}"
      data-pid="${p.id}" data-grp="${grp.id}"
      onclick="window.haut_tapChip('${p.id}','${grp.id}')">
      <div class="chip-main">
        ${done?'<span class="ck">✓</span>':''}
        ${p.name}
        ${ds&&!done?`<span class="chip-dose">${ds}</span>`:''}
        ${done?'<span class="chip-hint">⋯</span>':''}
        ${changed?'<span style="color:var(--accent);font-size:9px"> ✎</span>':''}
      </div>
      ${subText?`<div class="chip-sub">${subText}</div>`:''}
    </button>`;
  }).join('');

  const addBtn=delMode?'':`<button class="chip chip-add" onclick="window.haut_openNew('${grp.id}')">+</button>`;
  const hasComment=!!(comments[grp.id]&&comments[grp.id].trim());
  const commentIsOpen=!!commentOpen[grp.id];

  return `<div class="stack-card">
    <div class="stack-header" onclick="window.haut_toggleGrp('${grp.id}')">
      <span class="stack-label">${grp.label}</span>
      <span style="display:flex;align-items:center;gap:6px">
        <span class="stack-badge ${bc}">${bt}</span>
        <button class="comment-btn${hasComment?' has-comment':''}"
          onclick="event.stopPropagation();window.haut_toggleComment('${grp.id}')"
          title="${hasComment?'Kommentar bearbeiten':'Kommentar hinzufügen'}">💬</button>
        <span style="color:var(--muted);font-size:12px">${isOpen?'▲':'▼'}</span>
      </span>
    </div>
    ${isOpen?`<div class="stack-body">
      ${total>0?`<button class="btn-alle${allDone?' all-done':''}" onclick="window.haut_toggleAll('${grp.id}')">${allDone?'✓ Alle angewendet':'◎ Alle markieren'}</button>`:''}
      <div class="chip-row">${chips}${addBtn}</div>
      ${commentIsOpen?`
      <div class="comment-area">
        <textarea class="comment-textarea" id="comment-${grp.id}"
          placeholder="Kommentar zur ${grp.label}..."
        >${comments[grp.id]||''}</textarea>
        <div class="comment-actions">
          <button class="comment-clear" onclick="window.haut_clearComment('${grp.id}')">Leeren</button>
          <button class="comment-save" onclick="window.haut_saveComment('${grp.id}')">Speichern</button>
        </div>
      </div>`:
      hasComment?`<div class="comment-preview" onclick="window.haut_toggleComment('${grp.id}')">${escHtml(comments[grp.id])}</div>`:''}
    </div>`:''}
  </div>`;
}

function remaining(p){
  if(!p.intervalDays||!p.lastUsed)return 0;
  const diff=Math.round((new Date(today())-new Date(p.lastUsed))/(1000*60*60*24));
  return p.intervalDays-diff;
}

function toggleGrp(id){openGroups[id]=!openGroups[id];render()}

// ── COMMENTS ─────────────────────────────
function escHtml(s){return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}

function toggleComment(grpId){
  commentOpen[grpId]=!commentOpen[grpId];
  if(commentOpen[grpId]) openGroups[grpId]=true;
  render();
  if(commentOpen[grpId]){
    setTimeout(()=>{
      const ta=document.getElementById('comment-'+grpId);
      if(ta){ta.focus();ta.setSelectionRange(ta.value.length,ta.value.length)}
    },50);
  }
}

function saveComment(grpId){
  const ta=document.getElementById('comment-'+grpId);
  const val=ta?ta.value.trim():'';
  if(val){comments[grpId]=val;showToast('Kommentar gespeichert ✓')}
  else{delete comments[grpId];showToast('Kommentar entfernt')}
  commentOpen[grpId]=false;
  render();
}

function clearComment(grpId){
  const ta=document.getElementById('comment-'+grpId);
  if(ta) ta.value='';
}

// ── TAP + LONG PRESS ──────────────────────
function tapChip(pid,grp){
  const cur=isDone(pid,grp);
  if(cur){
    setDone(pid,grp,false);
    render();
  } else {
    setDone(pid,grp,true,null);
    // Update lastUsed for interval products
    const p=products.find(x=>x.id===pid);
    if(p&&p.intervalDays) p.lastUsed=today();
    showToast(`${p?.name} ✓`);
    render();
  }
}

document.addEventListener('click',e=>{
  if(lpFired){lpFired=false;e.stopImmediatePropagation();e.preventDefault();}
},true);

// ── ALLE ──────────────────────────────────
function toggleAll(grp){
  const prods=groupProds(grp);
  const all=prods.every(p=>isDone(p.id,grp));
  prods.forEach(p=>{
    setDone(p.id,grp,!all,null);
    if(!all&&p.intervalDays) p.lastUsed=today();
  });
  showToast(all?'Alle abgewählt':`Alle ${prods.length} angewendet ✓`);
  render();
}

// ── DELETE MODE ───────────────────────────
function toggleDelMode(){
  delMode=!delMode;
  const btn=document.getElementById('haut-btn-del');
  btn.classList.toggle('on',delMode);
  btn.textContent=delMode?'✓ Fertig':'🗑 Löschen';
  if(delMode)GROUPS.forEach(g=>openGroups[g.id]=true);
  render();
}
function delProd(pid,grp){
  const p=products.find(x=>x.id===pid);
  if(!p)return;
  p.groups=p.groups.filter(g=>g!==grp);
  if(!p.groups.length){products=products.filter(x=>x.id!==pid);showToast(`${p.name} entfernt`)}
  else showToast(`${p.name} aus Gruppe entfernt`);
  render();
}

// ── DOSE MODAL ────────────────────────────
function openDoseModal(pid,grp){
  const p=products.find(x=>x.id===pid);
  if(!p)return;
  doseCtx={pid,grp,p};
  document.getElementById('haut-m-dose-title').textContent=`✎ ${p.name} — Menge heute`;
  const cur=getODose(pid,grp)??p.dose;
  document.getElementById('haut-m-dose-val').value=cur||'';
  const ps=PRESETS[p.unit]||[];
  document.getElementById('haut-m-dose-quick').innerHTML=ps.map(v=>
    `<button class="db${parseFloat(cur)===v?' sel':''}" onclick="window.haut_pickDose(${v},this)">${v}${p.unit?' '+p.unit:''}</button>`
  ).join('');
  openModal('haut-m-dose');
}
function pickDose(v,btn){
  document.getElementById('haut-m-dose-val').value=v;
  btn.closest('.dq').querySelectorAll('.db').forEach(b=>b.classList.remove('sel'));
  btn.classList.add('sel');
}
function confirmDose(){
  if(!doseCtx)return;
  const {pid,grp,p}=doseCtx;
  const d=parseFloat(document.getElementById('haut-m-dose-val').value)||null;
  setDone(pid,grp,true,d);
  closeModal('haut-m-dose');doseCtx=null;
  showToast(`${p.name}${d&&p.unit?` · ${d} ${p.unit}`:''} ✓`);
  render();
}
function cancelDose(){
  if(!doseCtx)return;
  const {pid,grp,p}=doseCtx;
  setDone(pid,grp,false);
  closeModal('haut-m-dose');doseCtx=null;
  showToast(`${p.name} abgewählt`);
  render();
}

// ── EDIT PRODUCT ──────────────────────────
let editCtx = null;

function openEdit(pid){
  const p=products.find(x=>x.id===pid);
  if(!p)return;
  editCtx={pid};
  document.getElementById('haut-m-edit-sub').textContent=`ID: ${pid}`;
  document.getElementById('haut-m-edit-name').value=p.name;
  document.getElementById('haut-m-edit-unit').value=p.unit||'';
  document.getElementById('haut-m-edit-dose').value=p.dose||'';
  document.querySelectorAll('#haut-m-edit-stacks .stk-btn').forEach(b=>
    b.classList.toggle('sel',p.groups.includes(b.dataset.s)));
  const hasInterval=!!p.intervalDays;
  document.getElementById('haut-m-edit-interval-on').checked=hasInterval;
  document.getElementById('haut-m-edit-interval-days').disabled=!hasInterval;
  document.getElementById('haut-m-edit-interval-days').value=p.intervalDays||2;
  updateEditQuick();
  openModal('haut-m-edit');
  setTimeout(()=>document.getElementById('haut-m-edit-name').focus(),100);
}

function toggleEditIntervalInput(){
  const on=document.getElementById('haut-m-edit-interval-on').checked;
  document.getElementById('haut-m-edit-interval-days').disabled=!on;
}

function updateEditQuick(){
  const u=document.getElementById('haut-m-edit-unit').value;
  const cur=parseFloat(document.getElementById('haut-m-edit-dose').value);
  document.getElementById('haut-m-edit-quick').innerHTML=(PRESETS[u]||[]).map(v=>
    `<button class="db${cur===v?' sel':''}" onclick="window.haut_pickEdit(${v},this)">${v}${u?' '+u:''}</button>`
  ).join('');
}

function pickEdit(v,btn){
  document.getElementById('haut-m-edit-dose').value=v;
  btn.closest('.dq').querySelectorAll('.db').forEach(b=>b.classList.remove('sel'));
  btn.classList.add('sel');
}

function saveEdit(){
  if(!editCtx)return;
  const p=products.find(x=>x.id===editCtx.pid);
  if(!p)return;
  const name=document.getElementById('haut-m-edit-name').value.trim();
  const unit=document.getElementById('haut-m-edit-unit').value||null;
  const dose=parseFloat(document.getElementById('haut-m-edit-dose').value)||null;
  const groups=[...document.querySelectorAll('#haut-m-edit-stacks .stk-btn.sel')].map(b=>b.dataset.s);
  const intervalOn=document.getElementById('haut-m-edit-interval-on').checked;
  const intervalDays=intervalOn?parseInt(document.getElementById('haut-m-edit-interval-days').value)||null:null;
  if(!name){showToast('Name fehlt');return}
  if(!groups.length){showToast('Tageszeit wählen');return}
  p.name=name; p.unit=unit; p.dose=dose; p.groups=groups; p.intervalDays=intervalDays;
  products.sort((a,b)=>a.name.localeCompare(b.name,'de'));
  editCtx=null;
  closeModal('haut-m-edit');
  showToast(`${name} gespeichert ✓`);
  render();
}

// ── NEW PRODUCT MODAL ─────────────────────
function openNew(preGrp){
  document.getElementById('haut-m-new-name').value='';
  document.getElementById('haut-m-new-dose').value='';
  document.getElementById('haut-m-new-unit').value='';
  document.getElementById('haut-m-new-interval-on').checked=false;
  document.getElementById('haut-m-new-interval-days').disabled=true;
  document.getElementById('haut-m-new-interval-days').value=2;
  document.querySelectorAll('#haut-m-new-stacks .stk-btn').forEach(b=>
    b.classList.toggle('sel',b.dataset.s===preGrp));
  updateNewQuick();
  openModal('haut-m-new');
  setTimeout(()=>document.getElementById('haut-m-new-name').focus(),100);
}
function toggleIntervalInput(){
  const on=document.getElementById('haut-m-new-interval-on').checked;
  document.getElementById('haut-m-new-interval-days').disabled=!on;
}
function updateNewQuick(){
  const u=document.getElementById('haut-m-new-unit').value;
  const cur=parseFloat(document.getElementById('haut-m-new-dose').value);
  document.getElementById('haut-m-new-quick').innerHTML=(PRESETS[u]||[]).map(v=>
    `<button class="db${cur===v?' sel':''}" onclick="window.haut_pickNew(${v},this)">${v}${u?' '+u:''}</button>`
  ).join('');
}
function pickNew(v,btn){
  document.getElementById('haut-m-new-dose').value=v;
  btn.closest('.dq').querySelectorAll('.db').forEach(b=>b.classList.remove('sel'));
  btn.classList.add('sel');
}
function saveNew(){
  const name=document.getElementById('haut-m-new-name').value.trim();
  const unit=document.getElementById('haut-m-new-unit').value||null;
  const dose=parseFloat(document.getElementById('haut-m-new-dose').value)||null;
  const groups=[...document.querySelectorAll('#haut-m-new-stacks .stk-btn.sel')].map(b=>b.dataset.s);
  const intervalOn=document.getElementById('haut-m-new-interval-on').checked;
  const intervalDays=intervalOn?parseInt(document.getElementById('haut-m-new-interval-days').value)||null:null;
  if(!name){showToast('Name fehlt');return}
  if(!groups.length){showToast('Tageszeit wählen');return}
  const ex=products.find(p=>p.name.toLowerCase()===name.toLowerCase());
  if(ex){
    groups.forEach(g=>{if(!ex.groups.includes(g))ex.groups.push(g)});
    if(intervalDays)ex.intervalDays=intervalDays;
    showToast(`${name} aktualisiert`);
  } else {
    products.push({id:uid(),name,unit,dose,groups,intervalDays,lastUsed:null});
    products.sort((a,b)=>a.name.localeCompare(b.name,'de'));
    showToast(`${name} hinzugefügt`);
  }
  closeModal('haut-m-new');render();
}

// ── MODALS ────────────────────────────────
function openModal(id){document.getElementById(id).classList.add('open')}
function closeModal(id){document.getElementById(id).classList.remove('open')}

// ── TOAST ─────────────────────────────────
let tt;
function showToast(msg){
  const el=document.getElementById('toast');
  el.textContent=msg;el.classList.add('show');
  clearTimeout(tt);tt=setTimeout(()=>el.classList.remove('show'),2200);
}

// ── INIT ──────────────────────────────────
// Exports
window.haut_lpAction=function(btn){setTimeout(function(){if(window._lpFired!==undefined)window._lpFired=false;},50);if(typeof isDone==='function'&&!isDone(btn.dataset.pid,btn.dataset.grp))return;openDoseModal(btn.dataset.pid,btn.dataset.grp);};
  window.haut_clearComment = clearComment;
  window.haut_delProd = delProd;
  window.haut_openEdit = openEdit;
  window.haut_openNew = openNew;
  window.haut_pickDose = pickDose;
  window.haut_pickEdit = pickEdit;
  window.haut_pickNew = pickNew;
  window.haut_saveComment = saveComment;
  window.haut_tapChip = tapChip;
  window.haut_toggleAll = toggleAll;
  window.haut_toggleComment = toggleComment;
  window.haut_toggleGrp = toggleGrp;
  window.haut_cancelDose = cancelDose;
  window.haut_confirmDose = confirmDose;
  window.haut_render = render;
  window.haut_saveEdit = saveEdit;
  window.haut_saveNew = saveNew;
  window.haut_setSimDate = setSimDate;
  window.haut_toggleDelMode = toggleDelMode;
  window.haut_toggleEditIntervalInput = toggleEditIntervalInput;
  window.haut_toggleIntervalInput = toggleIntervalInput;
  window.haut_updateEditQuick = updateEditQuick;
  window.haut_updateNewQuick = updateNewQuick;
  window.haut_render = render;
})();

bef.js:
(function() {
// ── SKALEN ────────────────────────────────
const SCALES = {
  energie: [
    {v:1,label:'1'},{v:2,label:'2'},{v:3,label:'3'},{v:4,label:'4'},{v:5,label:'5'}
  ],
  stimmung: [
    {v:1,label:'1'},{v:2,label:'2'},{v:3,label:'3'},{v:4,label:'4'},{v:5,label:'5'}
  ],
  pain: [
    {v:0,label:'0'},{v:1,label:'1'},{v:2,label:'2'},{v:3,label:'3'},{v:4,label:'4'},{v:5,label:'5'}
  ],
  yesno: [
    {v:0,label:'Nein'},{v:1,label:'Ja'}
  ]
};

// ── METRIKEN (konfigurierbar) ─────────────
let metriken = [
  {id:'energie',  name:'Energie',    scale:'energie',  pflicht:true},
  {id:'stimmung', name:'Stimmung',   scale:'stimmung', pflicht:true},
];

function uid(){return Math.random().toString(36).slice(2,9)}

// ── STATE ─────────────────────────────────
// ankerData: { morgen: { energie:3, stimmung:4, entz:null, ... }, abend:{...} }
let ankerData = { morgen:{}, abend:{} };
let ankerOpen = { morgen:true, abend:false };
let ankerComments = { morgen:'', abend:'' };
let ankerCommentOpen = { morgen:false, abend:false };
// which optional metriken are active per anker
let activeOptional = { morgen: new Set(), abend: new Set() };
// spontaneous entries
let spontanList = [];
let krankData = { aktiv: false, kommentar: '' };

// ── RENDER ────────────────────────────────
function render(){
  // Krank toggle UI
  var kBtn=document.getElementById('bef-krank-btn');
  var kArea=document.getElementById('bef-krank-area');
  var kInput=document.getElementById('bef-krank-kommentar');
  if(kBtn){kBtn.style.borderColor=krankData.aktiv?'var(--delete)':'var(--border)';kBtn.style.color=krankData.aktiv?'var(--delete)':'var(--muted)';kBtn.style.background=krankData.aktiv?'color-mix(in srgb,var(--delete) 12%,var(--surface))':'none';kBtn.textContent=krankData.aktiv?'🤒 Krank: aktiv':'🤒 Krank';}
  if(kArea)kArea.style.display=krankData.aktiv?'block':'none';
  if(kInput&&document.activeElement!==kInput)kInput.value=krankData.kommentar||'';

  ['morgen','abend'].forEach(anker => {
    const body = document.getElementById('bef-body-'+anker);
    const arr = document.getElementById('bef-arr-'+anker);
    if(ankerOpen[anker]){
      body.style.display='block';
      arr.textContent='▲';
      renderMetrics(anker);
      renderCommentArea(anker);
    } else {
      body.style.display='none';
      arr.textContent='▼';
    }
    renderBadge(anker);
  });
  renderSpontan();
}

function renderBadge(anker){
  const badge = document.getElementById('bef-badge-'+anker);
  const cbtn = document.getElementById('bef-cbtn-'+anker);
  const data = ankerData[anker];
  const pflicht = metriken.filter(m=>m.pflicht);
  const filled = pflicht.filter(m=>data[m.id]!=null).length;
  if(filled===0){badge.textContent='—';badge.className='anker-badge'}
  else if(filled===pflicht.length){badge.textContent='✓';badge.className='anker-badge done'}
  else{badge.textContent=`${filled}/${pflicht.length}`;badge.className='anker-badge'}
  cbtn.classList.toggle('has-comment',!!(ankerComments[anker]));
}

function renderMetrics(anker){
  const container = document.getElementById('bef-metrics-'+anker);
  const data = ankerData[anker];
  const aktOpt = activeOptional[anker];

  // Pflicht metriken
  const pflichtHtml = metriken.filter(m=>m.pflicht).map(m=>renderMetricRow(m,anker,data[m.id])).join('');

  // Optionale die aktiv sind
  const optActiveHtml = metriken.filter(m=>!m.pflicht && aktOpt.has(m.id))
    .map(m=>renderMetricRow(m,anker,data[m.id],true)).join('');

  // Toggle-Buttons für optionale
  const optToggleHtml = metriken.filter(m=>!m.pflicht).map(m=>`
    <button class="opt-toggle-chip${aktOpt.has(m.id)?' active':''}"
      onclick="window.bef_toggleOptional('${anker}','${m.id}')">
      ${aktOpt.has(m.id)?'✓ ':'+ '}${m.name}
    </button>`).join('');

  container.innerHTML = `
    ${pflichtHtml}
    ${optActiveHtml}
    <div class="add-optional-row">${optToggleHtml}</div>
  `;
}

function renderMetricRow(m, anker, val, isOptional=false){
  const scale = SCALES[m.scale];
  const chips = scale.map(s=>{
    const isPain = m.scale==='pain';
    const isEn = m.scale==='energie' || m.scale==='stimmung';
    let colorClass = '';
    if(isPain) colorClass = 'pain-'+s.v;
    else if(isEn) colorClass = 'en-'+s.v;
    return `<button class="scale-chip${val===s.v?' selected':''} ${colorClass}"
      onclick="window.bef_setMetric('${anker}','${m.id}',${s.v})">
      <span class="sc-num">${s.label}</span>
    </button>`;
  }).join('');

  return `
    <div class="metric-row">
      <div class="metric-label-row">
        <span class="metric-label">${m.name}</span>
        ${val!=null ? `<span class="metric-value">${val}</span>` : ''}
      </div>
      <div class="chip-scale">${chips}</div>
    </div>`;
}

function renderCommentArea(anker){
  const container = document.getElementById('bef-comment-area-'+anker);
  const isOpen = ankerCommentOpen[anker];
  const comment = ankerComments[anker];
  if(isOpen){
    container.innerHTML = `
      <textarea class="comment-textarea" id="ta-${anker}"
        placeholder="Kommentar zum ${anker==='morgen'?'Morgen':'Abend'}..."
      >${comment}</textarea>
      <div class="comment-actions">
        <button class="comment-clear" onclick="document.getElementById('ta-${anker}').value=''">Leeren</button>
        <button class="comment-save" onclick="window.bef_saveComment('${anker}')">Speichern</button>
      </div>`;
    setTimeout(()=>{
      const ta=document.getElementById('bef-ta-'+anker);
      if(ta){ta.focus();ta.setSelectionRange(ta.value.length,ta.value.length)}
    },50);
  } else if(comment){
    container.innerHTML = `<div class="comment-preview" onclick="window.bef_toggleComment('${anker}')">${escHtml(comment)}</div>`;
  } else {
    container.innerHTML='';
  }
}

function renderSpontan(){
  const el = document.getElementById('bef-spontan-list');
  if(!spontanList.length){el.innerHTML='';return}
  el.innerHTML = spontanList.map(e=>`
    <div class="spontan-entry">
      <div class="spontan-time">${e.time}${e.label?' · '+e.label:''}</div>
      ${Object.entries(e.values).map(([mid,val])=>{
        const m=metriken.find(x=>x.id===mid);
        const s=SCALES[m?.scale||'energie'].find(x=>x.v===val);
        return `<span style="font-size:11px;margin-right:10px">${m?.name||mid}: ${s?.emoji||val} ${val}</span>`;
      }).join('')}
      <button class="spontan-del" onclick="window.bef_delSpontan('${e.id}')">✕</button>
    </div>`).join('');
}

// ── INTERACTIONS ──────────────────────────
function toggleAnker(id){
  ankerOpen[id]=!ankerOpen[id];
  render();
}

function setMetric(anker, metrikId, val){
  // Toggle: tap same value again = deselect
  if(ankerData[anker][metrikId]===val) ankerData[anker][metrikId]=null;
  else ankerData[anker][metrikId]=val;
  renderMetrics(anker);
  renderBadge(anker);
}

function toggleOptional(anker, metrikId){
  const s = activeOptional[anker];
  if(s.has(metrikId)){
    s.delete(metrikId);
    delete ankerData[anker][metrikId];
  } else {
    s.add(metrikId);
  }
  renderMetrics(anker);
}

// ── COMMENTS ─────────────────────────────
function escHtml(s){return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}

function toggleComment(anker){
  ankerCommentOpen[anker]=!ankerCommentOpen[anker];
  if(ankerCommentOpen[anker]) ankerOpen[anker]=true;
  render();
}

function saveComment(anker){
  const ta=document.getElementById('bef-ta-'+anker);
  ankerComments[anker]=ta?ta.value.trim():'';
  ankerCommentOpen[anker]=false;
  showToast(ankerComments[anker]?'Kommentar gespeichert ✓':'Kommentar entfernt');
  render();
}

// ── SPONTAN ───────────────────────────────
let spontanCtx = null;

function openSpontan(){
  spontanCtx = { editId: null };
  const now = new Date();
  document.getElementById('bef-m-spontan-time').value =
    `${String(now.getHours()).padStart(2,'0')}:${String(now.getMinutes()).padStart(2,'0')}`;
  document.getElementById('bef-m-spontan-label').value='';
  document.getElementById('bef-m-spontan-title').textContent='Befinden erfassen';
  document.getElementById('bef-m-spontan-sub').textContent='Spontaner Eintrag — wähle nur was relevant ist';
  renderSpontanMetrics({});
  openModal('bef-m-spontan');
}

function renderSpontanMetrics(vals){
  const container = document.getElementById('bef-m-spontan-metrics');
  container.innerHTML = metriken.map(m=>`
    <div class="metric-row">
      <div class="metric-label-row">
        <span class="metric-label">${m.name}${m.pflicht?'':' <span style="color:var(--muted);font-size:8px">opt.</span>'}</span>
        ${vals[m.id]!=null?`<span class="metric-value">${vals[m.id]}</span>`:''}
      </div>
      <div class="chip-scale">${SCALES[m.scale].map(s=>`
        <button class="scale-chip${vals[m.id]===s.v?' selected':''} ${m.scale==='pain'?'pain-'+s.v:(m.scale==='energie'||m.scale==='stimmung')?'en-'+s.v:''}"
          onclick="window.bef_setSpontanMetric('${m.id}',${s.v},this)"> 
          <span class="sc-num">${s.label}</span>
        </button>`).join('')}
      </div>
    </div>`).join('');
}

let spontanVals = {};
function setSpontanMetric(metrikId, val, btn){
  if(spontanVals[metrikId]===val) delete spontanVals[metrikId];
  else spontanVals[metrikId]=val;
  // Re-render just the chips in this row
  btn.closest('.chip-scale').querySelectorAll('.scale-chip').forEach(b=>{
    b.classList.toggle('selected', parseInt(b.querySelector('.sc-num').textContent)===spontanVals[metrikId]);
  });
  // Update value label
  const vLabel = btn.closest('.metric-row').querySelector('.metric-value');
  if(vLabel) vLabel.textContent = spontanVals[metrikId]??'';
  else if(spontanVals[metrikId]!=null){
    btn.closest('.metric-label-row')?.insertAdjacentHTML('beforeend',
      `<span class="metric-value">${spontanVals[metrikId]}</span>`);
  }
}

function saveSpontan(){
  const time = document.getElementById('bef-m-spontan-time').value;
  const label = document.getElementById('bef-m-spontan-label').value.trim();
  if(!Object.keys(spontanVals).length){ showToast('Mindestens eine Metrik wählen'); return; }
  spontanList.push({ id:uid(), time, label, values:{...spontanVals} });
  spontanList.sort((a,b)=>a.time.localeCompare(b.time));
  spontanVals={};
  closeModal('bef-m-spontan');
  render();
  showToast(`Befinden ${time} gespeichert ✓`);
}


// ── KRANK-TOGGLE ──────────────────────────
function toggleKrank() {
  krankData.aktiv = !krankData.aktiv;
  if(!krankData.aktiv) krankData.kommentar = '';
  render();
}

function saveKrankKommentar(){
  const val = document.getElementById('bef-krank-kommentar')?.value||'';
  krankData.kommentar = val;
  showToast('Gespeichert ✓');
}
function setKrankKommentar(val) {
  krankData.kommentar = val;
}
function delSpontan(id){
  spontanList=spontanList.filter(e=>e.id!==id);
  render();
}

// ── METRIKEN MANAGER ─────────────────────
function openMetrikMgr(){
  renderMgrList();
  openModal('bef-m-mgr');
}

function renderMgrList(){
  document.getElementById('bef-mgr-list').innerHTML = metriken.map(m=>`
    <div class="metric-mgr-chip${m.pflicht?' pflicht':''}" style="padding:5px 8px">
      <span>${m.name}</span>
      <span style="font-size:9px;color:var(--muted);margin:0 2px">${m.scale}</span>
      <button onclick="window.bef_togglePflicht('${m.id}')" title="${m.pflicht?'→ Optional':'→ Pflicht'}"
        style="background:none;border:none;font-size:10px;cursor:pointer;padding:0 2px;
          color:${m.pflicht?'var(--accent2)':'var(--muted)'}">
        ${m.pflicht?'★':'☆'}
      </button>
      <button onclick="window.bef_openEditMetrik('${m.id}')"
        style="background:none;border:1px solid var(--accent3);border-radius:10px;
          font-size:9px;color:var(--accent3);cursor:pointer;padding:1px 6px;
          font-family:'JetBrains Mono',monospace">✎</button>
      <button onclick="window.bef_delMetrik('${m.id}')"
        style="background:none;border:1px solid var(--delete);border-radius:10px;
          font-size:9px;color:var(--delete);cursor:pointer;padding:1px 6px">✕</button>
    </div>`).join('');
}

// ── EDIT METRIK ───────────────────────────
let editMetrikCtx = null;

function openEditMetrik(id){
  const m = metriken.find(x=>x.id===id);
  if(!m) return;
  editMetrikCtx = { id };
  document.getElementById('bef-m-edit-metrik-sub').textContent = `Metrik: ${m.name}`;
  document.getElementById('bef-edit-metrik-name').value = m.name;
  document.getElementById('bef-edit-metrik-scale').value = m.scale;
  setEditPflicht(m.pflicht);
  // close mgr first, open edit
  closeModal('bef-m-mgr');
  openModal('bef-m-edit-metrik');
  setTimeout(()=>document.getElementById('bef-edit-metrik-name').focus(), 100);
}

function setEditPflicht(val){
  document.getElementById('bef-edit-pflicht-btn').classList.toggle('sel', val);
  document.getElementById('bef-edit-optional-btn').classList.toggle('sel', !val);
  document.getElementById('bef-edit-pflicht-btn').dataset.val = val ? '1' : '0';
}

function saveEditMetrik(){
  if(!editMetrikCtx) return;
  const m = metriken.find(x=>x.id===editMetrikCtx.id);
  if(!m) return;
  const name = document.getElementById('bef-edit-metrik-name').value.trim();
  const scale = document.getElementById('bef-edit-metrik-scale').value;
  const pflicht = document.getElementById('bef-edit-pflicht-btn').dataset.val === '1';
  if(!name){ showToast('Name fehlt'); return; }
  m.name = name;
  m.scale = scale;
  m.pflicht = pflicht;
  editMetrikCtx = null;
  closeModal('bef-m-edit-metrik');
  // reopen manager
  openMetrikMgr();
  showToast(`${name} gespeichert ✓`);
  render();
}

function togglePflicht(id){
  const m=metriken.find(x=>x.id===id);
  if(m) m.pflicht=!m.pflicht;
  renderMgrList();
  render();
}

function delMetrik(id){
  metriken=metriken.filter(x=>x.id!==id);
  // Clean up data
  Object.keys(ankerData).forEach(a=>delete ankerData[a][id]);
  renderMgrList();
  render();
}

function addMetrik(){
  const name=document.getElementById('bef-mgr-new-name').value.trim();
  const scale=document.getElementById('bef-mgr-new-scale').value;
  const pflicht=document.getElementById('bef-mgr-new-pflicht').value==='pflicht';
  if(!name){showToast('Name fehlt');return}
  if(metriken.find(m=>m.name.toLowerCase()===name.toLowerCase())){showToast('Bereits vorhanden');return}
  metriken.push({id:uid(),name,scale,pflicht});
  document.getElementById('bef-mgr-new-name').value='';
  renderMgrList();
  render();
  showToast(`${name} hinzugefügt`);
}

// ── MODALS ────────────────────────────────
function openModal(id){
  spontanVals={};
  document.getElementById(id).classList.add('open');
}
function closeModal(id){document.getElementById(id).classList.remove('open')}

// ── TOAST ─────────────────────────────────
let tt;
function showToast(msg){
  const el=document.getElementById('toast');
  el.textContent=msg;el.classList.add('show');
  clearTimeout(tt);tt=setTimeout(()=>el.classList.remove('show'),2200);
}

// ── INIT ──────────────────────────────────
// Exports
  window.bef_delMetrik = delMetrik;
  window.bef_delSpontan = delSpontan;
  window.bef_openEditMetrik = openEditMetrik;
  window.bef_saveComment = saveComment;
  window.bef_setMetric = setMetric;
  window.bef_setSpontanMetric = setSpontanMetric;
  window.bef_toggleOptional = toggleOptional;
  window.bef_togglePflicht = togglePflicht;
  window.bef_addMetrik = addMetrik;
  window.bef_openMetrikMgr = openMetrikMgr;
  window.bef_openSpontan = openSpontan;
  window.bef_render = render;
  window.bef_saveEditMetrik = saveEditMetrik;
  window.bef_saveSpontan = saveSpontan;
  window.bef_setEditPflicht = setEditPflicht;
  window.bef_toggleAnker = toggleAnker;
  window.bef_toggleComment = toggleComment;
  window.bef_render = render;
  window.bef_toggleKrank = toggleKrank;
  window.bef_saveKrankKommentar = saveKrankKommentar;
  window.bef_setKrankKommentar = setKrankKommentar;
})();

entz.js:
(function() {
// ── SKALA ─────────────────────────────────
const SCALE = [
  {v:0,label:'0',desc:'Keine Veränderung'},
  {v:1,label:'1',desc:'Minimale Rötung, kaum sichtbar'},
  {v:2,label:'2',desc:'Deutliche Rötung, keine Beschwerden'},
  {v:3,label:'3',desc:'Rötung + Juckreiz / Spannung'},
  {v:4,label:'4',desc:'Starke Entzündung, Juckreiz, Schuppung'},
  {v:5,label:'5',desc:'Sehr stark, nässend oder aufgekratzt'},
];

const ANKER = ['morgen','abend'];

// ── STATE ─────────────────────────────────
// regions: [{id, name, groups:[]}]
let regions = [
  {id:'hals',    name:'Hals',              groups:['morgen','abend']},
  {id:'brust',   name:'Brust',             groups:['morgen','abend']},
  {id:'achsel',  name:'Linke Achsel',      groups:['morgen','abend']},
  {id:'ruecken', name:'Oberer Rücken',     groups:['morgen','abend']},
  {id:'kopfh',   name:'Kopfhaut',          groups:['morgen','abend']},
  {id:'gesicht', name:'Gesicht',           groups:['morgen','abend']},
  {id:'oberarm', name:'Oberarme',          groups:['morgen','abend']},
];
regions.sort((a,b)=>a.name.localeCompare(b.name,'de'));

// ankerData: { morgen: { regionId: 0-5|null }, abend: {...} }
let ankerData = { morgen:{}, abend:{} };
let ankerOpen = { morgen:true, abend:false };
let ankerComments = { morgen:'', abend:'' };
let ankerCommentOpen = { morgen:false, abend:false };
let spontanList = [];
let editRegionCtx = null;

// spontan temp values
let spontanVals = {};

function uid(){return Math.random().toString(36).slice(2,9)}
function escHtml(s){return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}

// ── RENDER ────────────────────────────────
function render(){
  ANKER.forEach(a=>{
    const body=document.getElementById('entz-body-'+a);
    const arr=document.getElementById('entz-arr-'+a);
    if(ankerOpen[a]){
      body.style.display='block';
      arr.textContent='▲';
      renderRegions(a);
      renderCommentArea(a);
    } else {
      body.style.display='none';
      arr.textContent='▼';
    }
    renderBadge(a);
  });
  renderSpontan();
}

function renderBadge(anker){
  const badge=document.getElementById('entz-badge-'+anker);
  const cbtn=document.getElementById('entz-cbtn-'+anker);
  const regs=regions.filter(r=>r.groups.includes(anker));
  const filled=regs.filter(r=>ankerData[anker][r.id]!=null).length;
  const hasHigh=regs.some(r=>(ankerData[anker][r.id]||0)>=3);
  if(filled===0){badge.textContent='—';badge.className='anker-badge'}
  else if(hasHigh){badge.textContent=`${filled}/${regs.length}`;badge.className='anker-badge active'}
  else{badge.textContent=`✓ ${filled}/${regs.length}`;badge.className='anker-badge done'}
  cbtn.classList.toggle('has-comment',!!ankerComments[anker]);
}


function copyFromPrevDay(anker) {
  // Get previous day's data from localStorage key
  const yesterday = new Date();
  yesterday.setDate(yesterday.getDate() - 1);
  const yKey = 'entz_' + yesterday.toISOString().slice(0,10);
  try {
    const prev = JSON.parse(localStorage.getItem(yKey) || '{}');
    if(prev[anker] && Object.keys(prev[anker]).length > 0) {
      ankerData[anker] = Object.assign({}, prev[anker]);
      render();
      showToast('Vortageswerte übernommen ✓');
    } else {
      showToast('Keine Vortageswerte vorhanden');
    }
  } catch(e) {
    showToast('Keine Vortageswerte vorhanden');
  }
}
function renderRegions(anker){
  const container=document.getElementById('entz-regions-'+anker);
  const regs=regions.filter(r=>r.groups.includes(anker));
  if(!regs.length){
    container.innerHTML=`<div style="font-size:11px;color:var(--muted);padding:8px 0">Keine Regionen konfiguriert</div>`;
    return;
  }
  container.innerHTML=regs.map(r=>{
    const val=ankerData[anker][r.id];
    const chips=SCALE.map(s=>`
      <button class="sv${val===s.v?' sel-'+s.v:''}"
        onclick="window.entz_setRegion('${anker}','${r.id}',${s.v})">
        <span class="sv-n">${s.label}</span>
      </button>`).join('');
    const selDesc = val!=null && SCALE[val] ? SCALE[val].desc : '';

    const valClass=val==null?'':val===0?'v0':val<=2?'v1':'v3';
    return `
      <div class="region-row">
        <div class="region-header">
          <span class="region-name">${r.name}</span>
          ${val!=null?`<span class="region-val ${valClass}">${SCALE[val]?.emoji} ${val}</span>`:''}
        </div>
        <div class="scale-row">${chips}</div>
      </div>`;
  }).join('');
}

function renderCommentArea(anker){
  const container=document.getElementById('entz-comment-area-'+anker);
  const isOpen=ankerCommentOpen[anker];
  const comment=ankerComments[anker];
  if(isOpen){
    container.innerHTML=`
      <textarea class="comment-textarea" id="ta-${anker}"
        placeholder="Kommentar zum ${anker==='morgen'?'Morgen':'Abend'}...">${comment}</textarea>
      <div class="comment-actions">
        <button class="comment-clear" onclick="document.getElementById('ta-${anker}').value=''">Leeren</button>
        <button class="comment-save" onclick="window.entz_saveComment('${anker}')">Speichern</button>
      </div>`;
    setTimeout(()=>{const ta=document.getElementById('entz-ta-'+anker);if(ta){ta.focus();ta.setSelectionRange(ta.value.length,ta.value.length)}},50);
  } else if(comment){
    container.innerHTML=`<div class="comment-preview" onclick="window.entz_toggleComment('${anker}')">${escHtml(comment)}</div>`;
  } else {
    container.innerHTML='';
  }
}

function renderSpontan(){
  const el=document.getElementById('entz-spontan-list');
  if(!spontanList.length){el.innerHTML='';return}
  el.innerHTML=spontanList.map(e=>`
    <div class="spontan-entry">
      <div class="spontan-time">${e.time}${e.note?' · '+e.note:''}</div>
      <div style="display:flex;flex-wrap:wrap">
        ${Object.entries(e.values).map(([rid,val])=>{
          const r=regions.find(x=>x.id===rid);
          const cls=val===0?'rp-0':val<=2?'rp-12':'rp-345';
          return `<span class="region-pill ${cls}">${r?.name||rid}: ${val}</span>`;
        }).join('')}
      </div>
      <button class="spontan-del" onclick="window.entz_delSpontan('${e.id}')">✕</button>
    </div>`).join('');
}

// ── INTERACTIONS ──────────────────────────
function toggleAnker(id){ankerOpen[id]=!ankerOpen[id];render()}

function setRegion(anker,regionId,val){
  if(ankerData[anker][regionId]===val) ankerData[anker][regionId]=null;
  else ankerData[anker][regionId]=val;
  renderRegions(anker);
  renderBadge(anker);
}

// ── COMMENTS ─────────────────────────────
function toggleComment(anker){
  ankerCommentOpen[anker]=!ankerCommentOpen[anker];
  if(ankerCommentOpen[anker]) ankerOpen[anker]=true;
  render();
}
function saveComment(anker){
  const ta=document.getElementById('entz-ta-'+anker);
  ankerComments[anker]=ta?ta.value.trim():'';
  ankerCommentOpen[anker]=false;
  showToast(ankerComments[anker]?'Kommentar gespeichert ✓':'Kommentar entfernt');
  render();
}

// ── DELETE MODE ───────────────────────────
function toggleDelMode(){
  delMode=!delMode;
  const btn=document.getElementById('btn-del');
  btn.classList.toggle('on',delMode);
  btn.textContent=delMode?'✓ Fertig':'🗑 Löschen';
  if(delMode) ANKER.forEach(a=>ankerOpen[a]=true);
  render();
}

// ── REGION MANAGER ────────────────────────
function openRegionMgr(){
  renderMgrChips();
  openModal('entz-m-mgr');
}

function renderMgrChips(){
  document.getElementById('entz-mgr-chips').innerHTML=regions.map(r=>`
    <div class="chip" style="flex-direction:row;align-items:center;gap:6px">
      <span>${r.name}</span>
      <span style="font-size:9px;color:var(--muted)">${r.groups.join('/')}</span>
      <button class="chip-edit-btn" onclick="window.entz_openEditRegion('${r.id}')">✎</button>
      <button class="chip-del-btn" onclick="window.entz_deleteRegion('${r.id}')">✕</button>
    </div>`).join('');
}

function openNewRegion(){
  editRegionCtx=null;
  document.getElementById('entz-m-region-title').textContent='Region anlegen';
  document.getElementById('entz-m-region-name').value='';
  document.querySelectorAll('#entz-m-region-grps .grp-btn').forEach(b=>b.classList.add('sel'));
  openModal('entz-m-region');
  setTimeout(()=>document.getElementById('entz-m-region-name').focus(),100);
}

function openEditRegion(rid){
  const r=regions.find(x=>x.id===rid);
  if(!r)return;
  editRegionCtx={rid};
  document.getElementById('entz-m-region-title').textContent='Region bearbeiten';
  document.getElementById('entz-m-region-name').value=r.name;
  document.querySelectorAll('#entz-m-region-grps .grp-btn').forEach(b=>
    b.classList.toggle('sel',r.groups.includes(b.dataset.g)));
  openModal('entz-m-region');
  setTimeout(()=>document.getElementById('entz-m-region-name').focus(),100);
}

function saveRegion(){
  const name=document.getElementById('entz-m-region-name').value.trim();
  const groups=[...document.querySelectorAll('#entz-m-region-grps .grp-btn.sel')].map(b=>b.dataset.g);
  if(!name){showToast('Name fehlt');return}
  if(!groups.length){showToast('Mindestens einen Block wählen');return}
  if(editRegionCtx){
    const r=regions.find(x=>x.id===editRegionCtx.rid);
    if(r){r.name=name;r.groups=groups;}
    showToast(`${name} gespeichert ✓`);
  } else {
    if(regions.find(r=>r.name.toLowerCase()===name.toLowerCase())){showToast('Bereits vorhanden');return}
    regions.push({id:uid(),name,groups});
    regions.sort((a,b)=>a.name.localeCompare(b.name,'de'));
    showToast(`${name} hinzugefügt`);
  }
  editRegionCtx=null;
  closeModal('entz-m-region');
  render();
}

function deleteRegion(rid){
  const r=regions.find(x=>x.id===rid);
  regions=regions.filter(x=>x.id!==rid);
  ANKER.forEach(a=>delete ankerData[a][rid]);
  showToast(`${r?.name} entfernt`);
  renderMgrChips();
  render();
}

// ── SPONTAN ───────────────────────────────
function openSpontan(){
  spontanVals={};
  const now=new Date();
  document.getElementById('entz-m-spontan-time').value=
    `${String(now.getHours()).padStart(2,'0')}:${String(now.getMinutes()).padStart(2,'0')}`;
  document.getElementById('entz-m-spontan-note').value='';
  renderSpontanRegions();
  openModal('entz-m-spontan');
}

function renderSpontanRegions(){
  document.getElementById('entz-m-spontan-regions').innerHTML=regions.map(r=>`
    <div class="region-row">
      <div class="region-header">
        <span class="region-name">${r.name}</span>
        ${spontanVals[r.id]!=null?`<span class="region-val">${SCALE[spontanVals[r.id]]?.emoji} ${spontanVals[r.id]}</span>`:''}
      </div>
      <div class="scale-row">${SCALE.map(s=>`
        <button class="sv${spontanVals[r.id]===s.v?' sel-'+s.v:''}"
          onclick="window.entz_setSpontanRegion('${r.id}',${s.v},this)">
          <span class="sv-n">${s.label}</span>
        </button>`).join('')}
      </div>
    </div>`).join('');
}

function setSpontanRegion(rid,val,btn){
  if(spontanVals[rid]===val) delete spontanVals[rid];
  else spontanVals[rid]=val;
  // update chips in this row
  btn.closest('.scale-row').querySelectorAll('.sv').forEach((b,i)=>{
    b.className='sv'+(spontanVals[rid]===i?' sel-'+i:'');
  });
  // update value display
  const hdr=btn.closest('.region-row').querySelector('.region-header');
  let vspan=hdr.querySelector('.region-val');
  if(spontanVals[rid]!=null){
    if(!vspan){vspan=document.createElement('span');vspan.className='region-val';hdr.appendChild(vspan)}
    vspan.textContent=`${SCALE[spontanVals[rid]]?.emoji} ${spontanVals[rid]}`;
  } else if(vspan) vspan.remove();
}

function saveSpontan(){
  const time=document.getElementById('entz-m-spontan-time').value;
  const note=document.getElementById('entz-m-spontan-note').value.trim();
  if(!Object.keys(spontanVals).length){showToast('Mindestens eine Region wählen');return}
  spontanList.push({id:uid(),time,note,values:{...spontanVals}});
  spontanList.sort((a,b)=>a.time.localeCompare(b.time));
  closeModal('entz-m-spontan');
  render();
  showToast(`Befund ${time} gespeichert ✓`);
}

function delSpontan(id){
  spontanList=spontanList.filter(e=>e.id!==id);
  render();
}

// ── MODALS ────────────────────────────────
function openModal(id){document.getElementById(id).classList.add('open')}
function closeModal(id){document.getElementById(id).classList.remove('open')}

// ── TOAST ─────────────────────────────────
let tt;
function showToast(msg){
  const el=document.getElementById('toast');
  el.textContent=msg;el.classList.add('show');
  clearTimeout(tt);tt=setTimeout(()=>el.classList.remove('show'),2200);
}

// ── INIT ──────────────────────────────────
// Exports
  window.entz_delSpontan = delSpontan;
  window.entz_deleteRegion = deleteRegion;
  window.entz_openEditRegion = openEditRegion;
  window.entz_saveComment = saveComment;
  window.entz_setRegion = setRegion;
  window.entz_setSpontanRegion = setSpontanRegion;
  window.entz_openNewRegion = openNewRegion;
  window.entz_openRegionMgr = openRegionMgr;
  window.entz_openSpontan = openSpontan;
  window.entz_render = render;
  window.entz_copyFromPrevDay = copyFromPrevDay;
  window.entz_saveRegion = saveRegion;
  window.entz_saveSpontan = saveSpontan;
  window.entz_toggleAnker = toggleAnker;
  window.entz_toggleComment = toggleComment;
  window.entz_render = render;
  window.entz_copyFromPrevDay = copyFromPrevDay;
})();

get.js:
(function() {
const ML_QUICK = [100,150,200,250,300,350,400,500,1000];
const BW_CYCLE = ['gut','unklar','schlecht'];
const BW_LABEL = {
  gut:     '✅ Gut für mich',
  unklar:  '❓ Unklar / noch beobachten',
  schlecht:'❌ Schlecht für mich'
};
const BW_ICON = { gut:'', unklar:'', schlecht:'' };
const BW_COLOR = { gut:'color-mix(in srgb,#27ae60 15%,var(--surface))', unklar:'color-mix(in srgb,var(--gold) 15%,var(--surface))', schlecht:'color-mix(in srgb,var(--delete) 15%,var(--surface))' };
const BW_BORDER = { gut:'#27ae60', unklar:'var(--gold)', schlecht:'var(--delete)' };

// ── TAGS ─────────────────────────────────
let tags = [
  {id:'tee',        emoji:'🍵', name:'Tee'},
  {id:'aufguss',    emoji:'🌿', name:'Aufguss'},
  {id:'koffein',    emoji:'☕', name:'Koffein'},
  {id:'alkohol',    emoji:'🍺', name:'Alkohol'},
  {id:'zucker',     emoji:'🍬', name:'Zucker'},
  {id:'fermentiert',emoji:'🧫', name:'Fermentiert'},
];

// ── GETRÄNKE ──────────────────────────────
let getraenke = [
  {id:'wasser',   name:'Wasser',      ml:300, tags:[],              bewertung:'gut'},
  {id:'kaffee',   name:'Kaffee',      ml:250, tags:['koffein'],     bewertung:'unklar'},
  {id:'oolong',   name:'Oolong',      ml:120, tags:['tee'],         bewertung:'gut'},
  {id:'gruentee', name:'Grüntee',     ml:250, tags:['tee'],         bewertung:'gut'},
  {id:'kamille',  name:'Kamillentee', ml:250, tags:['aufguss'],     bewertung:'gut'},
  {id:'kombucha', name:'Kombucha',    ml:250, tags:['fermentiert'], bewertung:'unklar'},
  {id:'bier',     name:'Bier',        ml:500, tags:['alkohol'],     bewertung:'schlecht'},
  {id:'redbull',  name:'Red Bull',    ml:250, tags:['koffein','zucker'], bewertung:'schlecht'},
];
getraenke.sort((a,b)=>a.name.localeCompare(b.name,'de')||a.ml-b.ml);

let entries = [];
let delMode = false;
let editMode = false;
let drinkCtx = null;
let editCtx = null;
let currentBewertung = 'gut';
let lpTimer = null, lpFired = false;

function uid(){return Math.random().toString(36).slice(2,9)}
function nowTime(){
  const n=new Date();
  return `${String(n.getHours()).padStart(2,'0')}:${String(n.getMinutes()).padStart(2,'0')}`;
}
function tagById(id){return tags.find(t=>t.id===id)}

// ── BEWERTUNG CYCLE ───────────────────────
function cycleBewertung(){
  const idx = BW_CYCLE.indexOf(currentBewertung);
  currentBewertung = BW_CYCLE[(idx+1) % BW_CYCLE.length];
  const btn = document.getElementById('get-bw-btn');
  btn.textContent = BW_LABEL[currentBewertung];
  btn.className = `bw-btn ${currentBewertung}`;
}
function setBewertung(val){
  currentBewertung = val || 'gut';
  const btn = document.getElementById('get-bw-btn');
  if(btn){ btn.textContent = BW_LABEL[currentBewertung]; btn.className = `bw-btn ${currentBewertung}`; }
}

// ── RENDER ────────────────────────────────
function render(){
  renderGetraenke();
  renderEntries();
}

function renderGetraenke(){
  const container = document.getElementById('get-getraenke-list');
  container.innerHTML = getraenke.map(g=>{
    const tagBadges = g.tags.map(tid=>{
      const t=tagById(tid);
      return t?`<span class="tag-badge tag-${tid}">${t.emoji}</span>`:'';
    }).join('');

    if(delMode){
      return `<div class="drink-chip del-mode" style="flex-direction:row;align-items:center;gap:8px">
        <div style="flex:1">
          <div class="dc-top"><span class="dc-name">${g.name}</span></div>
          <div class="dc-bottom"><span class="dc-ml">${g.ml}ml</span>${tagBadges}<span style="font-size:10px">${BW_ICON[g.bewertung||'gut']}</span></div>
        </div>
        <button class="chip-del-btn" onclick="event.stopPropagation();window.get_deleteGetraenk('${g.id}')">✕</button>
      </div>`;
    }

    if(editMode){
      return `<div class="drink-chip" style="border-color:var(--accent3);flex-direction:row;align-items:center;gap:8px">
        <div style="flex:1">
          <div class="dc-top"><span class="dc-name">${g.name}</span></div>
          <div class="dc-bottom"><span class="dc-ml">${g.ml}ml</span>${tagBadges}<span style="font-size:10px">${BW_ICON[g.bewertung||'gut']}</span></div>
        </div>
        <button class="chip-edit-btn" onclick="event.stopPropagation();window.get_openEditGetraenk('${g.id}')">✎</button>
      </div>`;
    }

    const bw = g.bewertung||'gut';
    return `<button class="chip" data-gid="${g.id}" onclick="window.get_quickDrink('${g.id}')"
      style="background:${BW_COLOR[bw]};border-color:${BW_BORDER[bw]}">
      ${g.name} <span style="font-size:10px;color:var(--muted)">${g.ml}ml</span>
    </button>`;
  }).join('') + `<button class="chip-add" onclick="window.get_openNewGetraenk()">+</button>`;
}




let _editEid = null;

function openEditMl(entryId) {
  const e = entries.find(x=>x.id===entryId);
  if(!e) { showToast('Eintrag nicht gefunden'); return; }
  _editEid = entryId;
  const g = getraenke.find(x=>x.id===e.getraenkId);
  const base = g ? g.ml : e.ml;
  const presets = [...new Set([
    Math.round(base*0.5), base, Math.round(base*1.5), base*2,
    100, 150, 200, 250, 330, 400, 500
  ])].filter(v=>v>=50&&v<=2000).sort((a,b)=>a-b);
  document.getElementById('get-edit-ml-title').textContent = e.name + ' — Menge';
  document.getElementById('get-edit-ml-val').value = e.ml;
  document.getElementById('get-edit-ml-presets').innerHTML = presets.map(v=>
    '<button class="chip" style="'+(v===e.ml?'background:var(--accent);color:#f5f0e8;border-color:var(--accent)':'')+'" onclick="document.getElementById(\'get-edit-ml-val\').value='+v+'">'+v+'ml</button>'
  ).join('');
  var modal = document.getElementById('get-edit-ml-modal');
  modal.style.display = 'flex';
}

function saveEditMl() {
  if(!_editEid) return;
  var val = parseInt(document.getElementById('get-edit-ml-val').value);
  if(!val||val<1) { showToast('Ungültige Menge'); return; }
  var idx = entries.findIndex(x=>x.id===_editEid);
  if(idx!==-1) entries[idx].ml = val;
  document.getElementById('get-edit-ml-modal').style.display = 'none';
  _editEid = null;
  render();
  showToast('Menge aktualisiert');
}



function showKommentar(entryId) {
  const e = entries.find(x=>x.id===entryId);
  if(e?.kommentar) showToast(e.kommentar);
}
function renderEntries(){
  const el = document.getElementById('get-entries-today');
  if(!entries.length){el.innerHTML='<span class="empty-hint">Noch nichts erfasst</span>';return}
  el.innerHTML=[...entries].sort((a,b)=>a.time.localeCompare(b.time)).map(e=>{
    const g = getraenke.find(x=>x.id===e.getraenkId);
    const bw = g?.bewertung || e.bewertung || 'gut';
    return '<button class="entry-chip '+bw+'" onclick="window.get_openEditMl(\''+e.id+'\')">' +
      e.name +
      '<span class="ec-ml">'+e.ml+'ml</span>'+
      '<span class="ec-time">'+e.time+'</span>'+
      (e.kommentar ? '<span ontouchend="event.preventDefault();event.stopPropagation();window.get_showKommentar(\''+e.id+'\')" style="font-size:11px;cursor:pointer;-webkit-user-select:none;-webkit-touch-callout:none">💬</span>' : '') +
      '<button class="ec-del" onclick="event.stopPropagation();window.get_deleteEntry(\''+e.id+'\')" style="-webkit-user-select:none">✕</button>'+
      '</button>';
  }).join('');
}

// ── QUICK DRINK ───────────────────────────
function quickDrink(gid){
  const g=getraenke.find(x=>x.id===gid);
  if(!g)return;
  entries.push({id:uid(),getraenkId:g.id,name:g.name,tags:g.tags,bewertung:g.bewertung||'gut',ml:g.ml,time:nowTime()});
  render();
  showToast(`${BW_ICON[g.bewertung||'gut']} ${g.name} · ${g.ml}ml ✓`);
}

// ── LONG PRESS ────────────────────────────
document.addEventListener('click',e=>{
  if(lpFired){lpFired=false;e.stopImmediatePropagation();e.preventDefault();}
},true);

function openDrinkModal(gid){
  const g=getraenke.find(x=>x.id===gid);
  if(!g)return;
  drinkCtx={gid};
  document.getElementById('get-m-drink-title').textContent=g.name;
  document.getElementById('get-m-drink-ml').value=g.ml;
  document.getElementById('get-m-drink-time').value=nowTime();
  document.getElementById('get-m-drink-quick').innerHTML=ML_QUICK.map(v=>
    `<button class="db${g.ml===v?' sel':''}" onclick="window.get_pickMl(${v},this)">${v} ml</button>`
  ).join('')+(ML_QUICK.includes(g.ml)?'':`<button class="db sel">${g.ml} ml ★</button>`);
  var k=document.getElementById('get-m-drink-kommentar');if(k)k.value='';
  openModal('get-m-drink');
}

function pickMl(v,btn){
  document.getElementById('get-m-drink-ml').value=v;
  btn.closest('.dq').querySelectorAll('.db').forEach(b=>b.classList.remove('sel'));
  btn.classList.add('sel');
}

function confirmDrink(){
  if(!drinkCtx)return;
  const g=getraenke.find(x=>x.id===drinkCtx.gid);
  if(!g)return;
  const ml=parseInt(document.getElementById('get-m-drink-ml').value)||g.ml;
  const time=document.getElementById('get-m-drink-time').value||nowTime();
  const kommentar = document.getElementById('get-m-drink-kommentar')?.value?.trim()||'';
  entries.push({id:uid(),getraenkId:g.id,name:g.name,tags:g.tags,bewertung:g.bewertung||'gut',ml,time});
  closeModal('get-m-drink');drinkCtx=null;
  render();
  showToast(`${BW_ICON[g.bewertung||'gut']} ${g.name} · ${ml}ml ✓`);
}

function deleteEntry(id){entries=entries.filter(e=>e.id!==id);render()}

// ── DELETE MODE ───────────────────────────
function toggleDelMode(){
  delMode=!delMode;
  if(delMode) { editMode=false; updateEditBtn(); }
  document.getElementById('get-btn-del').classList.toggle('on',delMode);
  document.getElementById('get-btn-del').textContent=delMode?'✓ Fertig':'🗑 Löschen';
  render();
}

function toggleEditMode(){
  editMode=!editMode;
  if(editMode) { delMode=false; document.getElementById('get-btn-del').classList.remove('on'); document.getElementById('get-btn-del').textContent='🗑 Löschen'; }
  updateEditBtn();
  render();
}

function updateEditBtn(){
  const btn=document.getElementById('get-btn-edit');
  btn.classList.toggle('on',editMode);
  btn.textContent=editMode?'✓ Fertig':'✎ Bearbeiten';
}
function deleteGetraenk(gid){
  const g=getraenke.find(x=>x.id===gid);
  getraenke=getraenke.filter(x=>x.id!==gid);
  entries=entries.filter(e=>e.getraenkId!==gid);
  showToast(`${g?.name} entfernt`);render();
}

// ── NEW / EDIT ────────────────────────────
function openNewGetraenk(){
  editCtx=null;
  document.getElementById('get-m-new-title').textContent='Getränk anlegen';
  document.getElementById('get-m-new-name').value='';
  document.getElementById('get-m-new-ml').value='';
  renderNewTags([]);
  updateNewQuick();
  openModal('get-m-new');
  setTimeout(()=>{setBewertung('gut');document.getElementById('get-m-new-name').focus();},50);
}

function openEditGetraenk(gid){
  const g=getraenke.find(x=>x.id===gid);
  if(!g)return;
  editCtx={gid};
  document.getElementById('get-m-new-title').textContent='Getränk bearbeiten';
  document.getElementById('get-m-new-name').value=g.name;
  document.getElementById('get-m-new-ml').value=g.ml;
  renderNewTags(g.tags);
  updateNewQuick();
  openModal('get-m-new');
  setTimeout(()=>{setBewertung(g.bewertung||'gut');document.getElementById('get-m-new-name').focus();},50);
}

function renderNewTags(selectedTags){
  document.getElementById('get-m-new-tags').innerHTML=tags.map(t=>`
    <button class="tag-btn tb-${t.id}${selectedTags.includes(t.id)?' sel':''}"
      onclick="this.classList.toggle('sel')" data-tid="${t.id}">
      ${t.emoji} ${t.name}
    </button>`).join('');
}

function updateNewQuick(){
  const cur=parseInt(document.getElementById('get-m-new-ml').value);
  document.getElementById('get-m-new-quick').innerHTML=ML_QUICK.map(v=>
    `<button class="db${cur===v?' sel':''}" onclick="window.get_pickNewMl(${v},this)">${v} ml</button>`
  ).join('');
}

function pickNewMl(v,btn){
  document.getElementById('get-m-new-ml').value=v;
  btn.closest('.dq').querySelectorAll('.db').forEach(b=>b.classList.remove('sel'));
  btn.classList.add('sel');
}

function saveGetraenk(){
  const name=document.getElementById('get-m-new-name').value.trim();
  const ml=parseInt(document.getElementById('get-m-new-ml').value)||0;
  const selTags=[...document.querySelectorAll('#get-m-new-tags .tag-btn.sel')].map(b=>b.dataset.tid);
  if(!name){showToast('Name fehlt');return}
  if(ml<=0){showToast('Volumen eingeben');return}
  if(editCtx){
    const g=getraenke.find(x=>x.id===editCtx.gid);
    if(g){g.name=name;g.ml=ml;g.tags=selTags;g.bewertung=currentBewertung;}
    showToast(`${name} gespeichert ✓`);
  } else {
    getraenke.push({id:uid(),name,ml,tags:selTags,bewertung:currentBewertung});
    showToast(`${name} hinzugefügt`);
  }
  getraenke.sort((a,b)=>a.name.localeCompare(b.name,'de')||a.ml-b.ml);
  editCtx=null;closeModal('get-m-new');render();
}

// ── TAG MANAGER ───────────────────────────
function openTagMgr(){renderTagMgrList();openModal('get-m-tags')}
function renderTagMgrList(){
  document.getElementById('get-tag-mgr-list').innerHTML=tags.map(t=>`
    <div class="tag-mgr-chip">${t.emoji} ${t.name}
      <button onclick="window.get_deleteTag('${t.id}')"
        style="background:none;border:none;color:var(--muted);font-size:11px;cursor:pointer;padding:0;margin-left:4px">✕</button>
    </div>`).join('');
}
function addTag(){
  const emoji=document.getElementById('get-new-tag-emoji').value.trim()||'🏷';
  const name=document.getElementById('get-new-tag-name').value.trim();
  if(!name){showToast('Name fehlt');return}
  tags.push({id:'c_'+uid(),emoji,name});
  document.getElementById('get-new-tag-emoji').value='';
  document.getElementById('get-new-tag-name').value='';
  renderTagMgrList();showToast(`"${name}" hinzugefügt`);
}
function deleteTag(id){
  tags=tags.filter(t=>t.id!==id);
  getraenke.forEach(g=>g.tags=g.tags.filter(tid=>tid!==id));
  renderTagMgrList();render();
}

// ── MODALS ────────────────────────────────
function openModal(id){document.getElementById(id).classList.add('open')}
function closeModal(id){document.getElementById(id).classList.remove('open')}

// ── TOAST ─────────────────────────────────
let tt;
function showToast(msg){
  const el=document.getElementById('toast');
  el.textContent=msg;el.classList.add('show');
  clearTimeout(tt);tt=setTimeout(()=>el.classList.remove('show'),2200);
}
// Exports
window.get_lpAction=function(btn){setTimeout(function(){if(window._lpFired!==undefined)window._lpFired=false;},50);if(typeof openDrinkModal==='function')openDrinkModal(btn.dataset.gid);};
  window.get_deleteEntry = deleteEntry;
  window.get_deleteGetraenk = deleteGetraenk;
  window.get_deleteTag = deleteTag;
  window.get_openEditGetraenk = openEditGetraenk;
  window.get_pickMl = pickMl;
  window.get_pickNewMl = pickNewMl;
  window.get_quickDrink = quickDrink;
  window.get_addTag = addTag;
  window.get_confirmDrink = confirmDrink;
  window.get_cycleBewertung = cycleBewertung;
  window.get_openNewGetraenk = openNewGetraenk;
  window.get_openTagMgr = openTagMgr;
  window.get_render = render;
  window.get_showKommentar = showKommentar;
  window.get_saveGetraenk = saveGetraenk;
  window.get_toggleDelMode = toggleDelMode;
  window.get_toggleEditMode = toggleEditMode;
  window.get_updateNewQuick = updateNewQuick;
  window.get_render = render;
  window.get_showKommentar = showKommentar;
  window.get_openEditMl = openEditMl;
  window.get_saveEditMl = saveEditMl;
})();

