(function() {
const BW_CYCLE = ['gut','unklar','schlecht'];
const BW_LABEL = { gut:'✅ Gut für mich', unklar:'❓ Unklar / noch beobachten', schlecht:'❌ Schlecht für mich' };
const BW_ICON  = { gut:'✅', unklar:'❓', schlecht:'❌' };
const BW_COLOR = { gut:'color-mix(in srgb,#27ae60 15%,var(--surface))', unklar:'color-mix(in srgb,var(--gold) 15%,var(--surface))', schlecht:'color-mix(in srgb,var(--delete) 15%,var(--surface))' };
const BW_BORDER = { gut:'#27ae60', unklar:'var(--gold)', schlecht:'var(--delete)' };
const MENGE_QUICK = ['50g','100g','150g','200g','1 Stk','2 Stk','1 EL','2 EL','1 Portion'];

const MEALS = [
  {id:'fruehstueck', label:'🌅 Frühstück'},
  {id:'mittagessen', label:'☀️ Mittagessen'},
  {id:'abendessen',  label:'🌆 Abendessen'},
  {id:'snack',       label:'🍎 Snack'},
];

// ── BIBLIOTHEK ────────────────────────────
let bibliothek = [
  {id:'haferflocken', name:'Haferflocken',  type:'lebensmittel', zutaten:[], bewertung:'gut'},
  {id:'apfel',        name:'Apfel',         type:'lebensmittel', zutaten:[], bewertung:'gut'},
  {id:'blaubeeren',   name:'Blaubeeren',    type:'lebensmittel', zutaten:[], bewertung:'gut'},
  {id:'eier',         name:'Eier',          type:'lebensmittel', zutaten:[], bewertung:'gut'},
  {id:'lachs',        name:'Lachs',         type:'lebensmittel', zutaten:[], bewertung:'gut'},
  {id:'brokkoli',     name:'Brokkoli',      type:'lebensmittel', zutaten:[], bewertung:'gut'},
  {id:'suessk',       name:'Süßkartoffel',  type:'lebensmittel', zutaten:[], bewertung:'gut'},
  {id:'joghurt',      name:'Joghurt',       type:'lebensmittel', zutaten:[], bewertung:'unklar'},
  {id:'brot',         name:'Brot (Weizen)', type:'lebensmittel', zutaten:[], bewertung:'unklar'},
  {id:'bonbon',       name:'Bonbon',        type:'lebensmittel', zutaten:[], bewertung:'schlecht'},
  {id:'schwein',      name:'Schweinefleisch',  type:'lebensmittel', zutaten:[], bewertung:'gut'},
  {id:'paniermehl',    name:'Paniermehl',       type:'lebensmittel', zutaten:[], bewertung:'unklar'},
  {id:'zitrone',       name:'Zitrone',          type:'lebensmittel', zutaten:[], bewertung:'gut'},
  {id:'schnitzel',     name:'Wiener Schnitzel', type:'gericht',      zutaten:[{id:'schwein',menge:'200g'},{id:'paniermehl',menge:'50g'},{id:'eier',menge:'1 Stk'},{id:'zitrone',menge:'½ Stk'}], bewertung:'unklar'},
];
bibliothek.sort((a,b)=>a.name.localeCompare(b.name,'de'));

// mealEntries: { mahlzeitId: [{id, itemId, name, menge, bewertung}] }
let mealEntries = { fruehstueck:[], mittagessen:[], abendessen:[], snack:[] };
let mealOpen    = { fruehstueck:false, mittagessen:true, abendessen:false, snack:false };
let mealComments = { fruehstueck:'', mittagessen:'', abendessen:'', snack:'' };
let mealCommentOpen = { fruehstueck:false, mittagessen:false, abendessen:false, snack:false };

let delMode = false, editMode = false;
let moveCtx = null;
let entryLpTimer = null, entryLpFired = false;
let spontanEntries = [];
let spontanSelected = new Set();
let addCtx = null, editCtx = null;
let currentBewertung = 'gut';
let lpTimer = null, lpFired = false;


function gerichtBewertung(item) {
  if(item.type !== 'gericht') return item.bewertung;
  const zutaten = item.zutaten||[];
  if(!zutaten.length) return 'unklar';
  const bws = zutaten.map(z => {
    const zid = typeof z === 'string' ? z : z.id;
    const zutat = bibliothek.find(x=>x.id===zid);
    return zutat ? zutat.bewertung : 'unklar';
  });
  if(bws.includes('schlecht')) return 'schlecht';
  if(bws.includes('unklar')) return 'unklar';
  return 'gut';
}

function gerichtZutaten(item) {
  // normalize zutaten to [{id, menge}]
  return (item.zutaten||[]).map(z => typeof z === 'string' ? {id:z, menge:''} : z);
}

function canDeleteItem(itemId) {
  // Check if used in any gericht
  const usedIn = bibliothek.filter(g =>
    g.type === 'gericht' && gerichtZutaten(g).some(z => z.id === itemId)
  );
  return usedIn.length === 0 ? null : usedIn.map(g => g.name).join(', ');
}

function uid(){ return Math.random().toString(36).slice(2,9); }
function nowTime(){
  const n=new Date();
  return `${String(n.getHours()).padStart(2,'0')}:${String(n.getMinutes()).padStart(2,'0')}`;
}
function escHtml(s){ return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
function itemById(id){ return bibliothek.find(x=>x.id===id); }

// ── BEWERTUNG ─────────────────────────────
function toggleZutatenSection(){
  const type = document.getElementById('ern-m-new-type').value;
  const sec = document.getElementById('ern-zutaten-section');
  if(sec) sec.style.display = type==='gericht' ? 'block' : 'none';
  if(type==='gericht') renderZutatenChips();
}

let selectedZutaten = new Map(); // id → menge


function toggleZutat(id){
  if(selectedZutaten.has(id)) selectedZutaten.delete(id);
  else selectedZutaten.set(id,'');
  renderZutatenChips();
}
function setZutatMenge(id, menge){
  if(selectedZutaten.has(id)) selectedZutaten.set(id, menge);
}
function renderZutatenChips(){
  const container = document.getElementById('ern-m-new-zutaten-chips');
  if(!container) return;
  const lm = bibliothek.filter(x=>x.type==='lebensmittel');
  // Selected zutaten with menge inputs
  const selectedHtml = [...selectedZutaten.entries()].map(([id,menge])=>{
    const item = bibliothek.find(x=>x.id===id);
    if(!item) return '';
    const bw = item.bewertung||'gut';
    return `<div style="display:flex;align-items:center;gap:5px;margin-bottom:5px">
      <button class="chip" style="background:${BW_COLOR[bw]};border-color:${BW_BORDER[bw]};flex:1">${item.name}</button>
      <input class="mi" value="${menge}" placeholder="Menge"
        style="width:80px;margin:0;font-size:11px;padding:4px 8px"
        oninput="window.ern_setZutatMenge('${id}',this.value)">
      <button onclick="window.ern_toggleZutat('${id}')"
        style="background:none;border:none;color:var(--muted);font-size:16px;cursor:pointer;padding:0 4px">✕</button>
    </div>`;
  }).join('');
  // Available lebensmittel
  const selectedIds = [...selectedZutaten.keys()];
  const availableHtml = lm.filter(l=>!selectedIds.includes(l.id)).map(l=>{
    const bw = l.bewertung||'gut';
    return `<button class="chip" style="background:${BW_COLOR[bw]};border-color:${BW_BORDER[bw]}"
      onclick="window.ern_toggleZutat('${l.id}')">${l.name}</button>`;
  }).join('');
  // Auto bewertung
  const autoBw = selectedZutaten.size > 0 ? (
    [...selectedZutaten.keys()].some(id=>{const i=bibliothek.find(x=>x.id===id);return i?.bewertung==='schlecht';}) ? 'schlecht' :
    [...selectedZutaten.keys()].some(id=>{const i=bibliothek.find(x=>x.id===id);return i?.bewertung==='unklar';}) ? 'unklar' : 'gut'
  ) : null;
  // Hide manual bewertung for gerichte
  const bwSection = document.getElementById('ern-bewertung-section');
  if(bwSection) bwSection.style.display = 'none';
  const autoBwEl = document.getElementById('ern-auto-bewertung');
  if(autoBwEl && autoBw) {
    autoBwEl.style.display = 'block';
    autoBwEl.style.background = BW_COLOR[autoBw];
    autoBwEl.style.borderColor = BW_BORDER[autoBw];
    autoBwEl.textContent = 'Bewertung: ' + (autoBw==='gut'?'✅ Gut':autoBw==='unklar'?'❓ Unklar':'❌ Schlecht');
  }
  container.innerHTML = (selectedHtml ? `<div style="margin-bottom:8px">${selectedHtml}</div>` : '') +
    `<div style="font-size:9px;color:var(--muted);margin-bottom:4px">HINZUFÜGEN</div>` +
    `<div style="display:flex;flex-wrap:wrap;gap:5px">${availableHtml||'<span style="font-size:11px;color:var(--muted)">Alle bereits ausgewählt</span>'}</div>`;
}

function toggleZutat(id){
  if(selectedZutaten.has(id)) selectedZutaten.delete(id);
  else selectedZutaten.add(id);
  renderZutatenChips();
}

function cycleBewertung(){
  const idx = BW_CYCLE.indexOf(currentBewertung);
  currentBewertung = BW_CYCLE[(idx+1) % BW_CYCLE.length];
  const btn = document.getElementById('ern-bw-btn');
  btn.textContent = BW_LABEL[currentBewertung];
  btn.className = `bw-btn ${currentBewertung}`;
}
function setBewertung(val){
  currentBewertung = val || 'gut';
  const btn = document.getElementById('ern-bw-btn');
  if(btn){ btn.textContent = BW_LABEL[currentBewertung]; btn.className = `bw-btn ${currentBewertung}`; }
}

// ── RENDER ────────────────────────────────
function render(){
  renderMeals();
  renderBibliothek();
  renderSpontan();
}

function renderSpontan(){
  const el = document.getElementById('ern-spontan-list');
  if(!spontanEntries.length){ el.innerHTML=''; return; }
  el.innerHTML = spontanEntries.sort((a,b)=>a.time.localeCompare(b.time)).map(e=>`
    <div class="meal-entry" style="margin-bottom:5px">
      <span class="me-icon">🕐</span>
      <div style="flex:1">
        <div style="font-size:10px;color:var(--gold)">${e.time}${e.label?' · '+e.label:''}</div>
        <div style="display:flex;flex-wrap:wrap;gap:4px;margin-top:3px">
          ${e.items.map(i=>`<span style="font-size:11px">${BW_ICON[i.bewertung||'gut']} ${escHtml(i.name)}${i.menge?' ('+i.menge+')':''}</span>`).join(' · ')}
        </div>
      </div>
      <button class="me-del" onclick="window.ern_deleteSpontan('${e.id}')">✕</button>
    </div>`).join('');
}

function openSpontanModal(){
  spontanSelected = new Set();
  document.getElementById('ern-sp-time').value = nowTime();
  document.getElementById('ern-sp-label').value = '';
  document.getElementById('ern-sp-custom').value = '';
  renderSpItemChips();
  openModal('ern-m-spontan');
}

function renderSpItemChips(){
  document.getElementById('ern-sp-item-chips').innerHTML = bibliothek.map(item=>`
    <button class="item-chip${spontanSelected.has(item.id)?' sel':''}  ${item.bewertung}"
      style="${spontanSelected.has(item.id)?'background:color-mix(in srgb,var(--accent2) 15%,var(--surface2));border-color:var(--accent2)':''}"
      onclick="window.ern_toggleSpItem('${item.id}')">
      <div class="ic-name">${BW_ICON[item.bewertung]} ${item.name}</div>
    </button>`).join('');
}

function toggleSpItem(itemId){
  if(spontanSelected.has(itemId)) spontanSelected.delete(itemId);
  else spontanSelected.add(itemId);
  renderSpItemChips();
}

function saveSpontan(){
  const time  = document.getElementById('ern-sp-time').value || nowTime();
  const label = document.getElementById('ern-sp-label').value.trim();
  const custom = document.getElementById('ern-sp-custom').value.trim();
  const items = [...spontanSelected].map(id=>{
    const item = itemById(id);
    return { name:item.name, bewertung:item.bewertung||'gut' };
  });
  if(custom) items.push({ name:custom, bewertung:'unklar' });
  if(!items.length){ showToast('Bitte etwas auswählen oder eingeben'); return; }
  spontanEntries.push({ id:uid(), time, label, items });
  closeModal('ern-m-spontan');
  render();
  showToast(`${items.length} Item${items.length>1?'s':''} um ${time} ✓`);
}

function deleteSpontan(id){
  spontanEntries = spontanEntries.filter(e=>e.id!==id);
  render();
}

function renderMeals(){
  document.getElementById('ern-meals-container').innerHTML = MEALS.map(m=>{
    const entries = mealEntries[m.id];
    const isOpen  = mealOpen[m.id];
    const hasComment = !!mealComments[m.id];
    const commentIsOpen = mealCommentOpen[m.id];
    const badge = entries.length ? `<span class="meal-badge has-entries">✓ ${entries.length}</span>` : `<span class="meal-badge">—</span>`;

    const entryList = entries.length ? `
      <div class="meal-entries">
        ${entries.map(e=>{
          const live = itemById(e.itemId);
          const bw = live?.bewertung || e.bewertung || 'gut';
          // Is this a Gericht? Render header + indented zutaten
          if(live?.type==='gericht' && live.zutaten?.length){
            const zutatItems = live.zutaten.map(zid=>itemById(zid)).filter(Boolean);
            const zutatRows = zutatItems.map(z=>`<button class="chip" style="font-size:10px;opacity:0.8;background:${BW_COLOR[z.bewertung||'gut']};border-color:${BW_BORDER[z.bewertung||'gut']}">${escHtml(z.name)}</button>`).join('');
            return `<div style="display:flex;flex-wrap:wrap;gap:4px;margin-bottom:2px">
              <button class="chip" style="background:${BW_COLOR[bw]};border-color:${BW_BORDER[bw]};border-left:3px solid var(--c-ern)"
                data-meal="${m.id}" data-entry="${e.id}">
                🍽 ${escHtml(e.name)}${e.menge?` <span style="font-size:10px;opacity:0.7">${escHtml(e.menge)}</span>`:''}
                <button class="me-del" onclick="event.stopPropagation();window.ern_deleteEntry('${m.id}','${e.id}')">✕</button>
              </button>
              ${zutatRows}
            </div>`;
          }
          return `<button class="chip" style="background:${BW_COLOR[bw]};border-color:${BW_BORDER[bw]}"
            data-meal="${m.id}" data-entry="${e.id}">
            ${escHtml(e.name)}${e.menge?` <span style="font-size:10px;opacity:0.7">${escHtml(e.menge)}</span>`:''}
            <button class="me-del" onclick="event.stopPropagation();window.ern_deleteEntry('${m.id}','${e.id}')">✕</button>
          </button>`;
        }).join('')}
      </div>` : '';

    const commentHtml = isOpen ? (commentIsOpen ? `
      <div style="margin-top:8px;border-top:1px solid var(--border);padding-top:8px">
        <textarea class="comment-textarea" id="ta-${m.id}"
          placeholder="Notiz zu ${m.label}...">${mealComments[m.id]}</textarea>
        <div class="comment-actions">
          <button class="comment-clear" onclick="document.getElementById('ta-${m.id}').value=''">Leeren</button>
          <button class="comment-save" onclick="window.ern_saveComment('${m.id}')">Speichern</button>
        </div>
      </div>` :
      mealComments[m.id] ? `<div class="comment-preview" onclick="window.ern_toggleComment('${m.id}')">${escHtml(mealComments[m.id])}</div>` : ''
    ) : '';

    return `<div class="meal-card">
      <div class="meal-header" onclick="window.ern_toggleMeal('${m.id}')">
        <span class="meal-label">${m.label}</span>
        <span style="display:flex;align-items:center;gap:6px">
          ${badge}
          <button class="comment-btn${hasComment?' has-comment':''}"
            onclick="event.stopPropagation();window.ern_toggleComment('${m.id}')">💬</button>
          <span style="color:var(--muted);font-size:12px">${isOpen?'▲':'▼'}</span>
        </span>
      </div>
      ${isOpen?`<div class="meal-body">
        ${entryList}
        ${commentHtml}
      </div>`:''}
    </div>`;
  }).join('');
}

function renderBibliothek(){
  // Update target indicator
  const openMeal = MEALS.find(m=>mealOpen[m.id]);
  const ind = document.getElementById('ern-target-indicator');
  if(ind){
    if(openMeal){ ind.textContent='→ '+openMeal.label; ind.style.display=''; }
    else { ind.textContent='Mahlzeit öffnen'; ind.style.borderColor='var(--muted)'; ind.style.color='var(--muted)'; }
  }
  const container = document.getElementById('ern-bibliothek-list');
  container.innerHTML = bibliothek.map(item=>{
    if(delMode){
      const bw3 = item.bewertung||'unklar';
      return `<button class="chip" style="background:${BW_COLOR[bw3]};border-color:${BW_BORDER[bw3]}">
        ${item.name}
        <button class="chip-del-btn" onclick="event.stopPropagation();window.ern_deleteItem('${item.id}')">✕</button>
      </button>`;
    }
    if(editMode){
      const bw2 = item.bewertung||'unklar';
      return `<button class="chip" style="background:${BW_COLOR[bw2]};border-color:${BW_BORDER[bw2]}">
        ${item.name}
        <button class="chip-edit-btn" onclick="event.stopPropagation();window.ern_openEditItem('${item.id}')">✎</button>
      </button>`;
    }
    const bw = item.type==='gericht' ? gerichtBewertung(item) : (item.bewertung||'unklar');
    return `<button class="chip" data-iid="${item.id}"
      onclick="window.ern_quickAdd('${item.id}')"
      style="background:${BW_COLOR[bw]};border-color:${BW_BORDER[bw]}">${item.name}</button>`;
  }).join('') + (!delMode&&!editMode?`<button class="chip-add" onclick="window.ern_openNewItem()">+</button>`:'');
}

// ── MEAL INTERACTIONS ─────────────────────
function toggleMeal(id){
  const wasOpen = mealOpen[id];
  // close all
  Object.keys(mealOpen).forEach(k=>mealOpen[k]=false);
  // open clicked one only if it was closed
  if(!wasOpen) mealOpen[id]=true;
  render();
}

function deleteEntry(mealId, entryId){
  mealEntries[mealId] = mealEntries[mealId].filter(e=>e.id!==entryId);
  render();
}

// ── COMMENTS ─────────────────────────────
function toggleComment(mealId){
  mealCommentOpen[mealId]=!mealCommentOpen[mealId];
  if(mealCommentOpen[mealId]) mealOpen[mealId]=true;
  render();
  if(mealCommentOpen[mealId]){
    setTimeout(()=>{const ta=document.getElementById('ta-'+mealId);if(ta){ta.focus();ta.setSelectionRange(ta.value.length,ta.value.length)}},50);
  }
}
function saveComment(mealId){
  const ta=document.getElementById('ta-'+mealId);
  mealComments[mealId]=ta?ta.value.trim():'';
  mealCommentOpen[mealId]=false;
  showToast(mealComments[mealId]?'Kommentar gespeichert ✓':'Kommentar entfernt');
  render();
}

// ── QUICK ADD (kurzer Tap) ─────────────────
function quickAdd(itemId){
  const targetMeal = MEALS.find(m=>mealOpen[m.id])?.id;
  if(!targetMeal){
    showToast('Bitte zuerst eine Mahlzeit öffnen');
    return;
  }
  const item = itemById(itemId);
  if(!item) return;
  mealEntries[targetMeal].push({ id:uid(), itemId, name:item.name, menge:'', bewertung:item.bewertung });
  render();
  showToast(`${BW_ICON[item.bewertung]} ${item.name} → ${MEALS.find(m=>m.id===targetMeal)?.label}`);
}

// ── LONG PRESS → modal ────────────────────
document.addEventListener('click',e=>{
  if(lpFired){lpFired=false;e.stopImmediatePropagation();e.preventDefault();}
},true);

function openAddModal(itemId){
  const item = itemById(itemId);
  if(!item) return;
  addCtx = {itemId};
  document.getElementById('ern-m-add-title').textContent = `${BW_ICON[item.bewertung]} ${item.name}`;
  document.getElementById('ern-m-add-menge').value = '';
  // Populate meal select
  const openMeal = MEALS.find(m=>mealOpen[m.id]);
  document.getElementById('ern-m-add-meal').innerHTML = MEALS.map(m=>
    `<option value="${m.id}"${m.id===(openMeal?.id||'fruehstueck')?' selected':''}>${m.label}</option>`
  ).join('');
  // Quick presets
  document.getElementById('ern-m-add-quick').innerHTML = MENGE_QUICK.map(v=>
    `<button class="db" onclick="window.ern_pickMenge('${v}',this)">${v}</button>`
  ).join('');
  openModal('ern-m-add');
}

function pickMenge(v,btn){
  document.getElementById('ern-m-add-menge').value=v;
  btn.closest('.dq').querySelectorAll('.db').forEach(b=>b.classList.remove('sel'));
  btn.classList.add('sel');
}

function confirmAdd(){
  if(!addCtx) return;
  const item = itemById(addCtx.itemId);
  if(!item) return;
  const mealId = document.getElementById('ern-m-add-meal').value;
  const menge  = document.getElementById('ern-m-add-menge').value.trim();
  mealEntries[mealId].push({ id:uid(), itemId:item.id, name:item.name, menge, bewertung:item.bewertung });
  closeModal('ern-m-add'); addCtx=null;
  render();
  showToast(`${BW_ICON[item.bewertung]} ${item.name}${menge?' · '+menge:''} ✓`);
}

// ── BIBLIOTHEK CRUD ───────────────────────
function openNewItem(){
  editCtx=null;
  selectedZutaten = new Set();
  document.getElementById('ern-m-new-title').textContent='Lebensmittel anlegen';
  document.getElementById('ern-m-new-name').value='';
  document.getElementById('ern-m-new-type').value='lebensmittel';
  const sec=document.getElementById('ern-zutaten-section');
  if(sec) sec.style.display='none';
  openModal('ern-m-new');
  setTimeout(()=>{setBewertung('gut');document.getElementById('ern-m-new-name').focus();},50);
}

function openEditItem(itemId){
  const item=itemById(itemId);
  if(!item) return;
  editCtx={itemId};
  selectedZutaten = new Map();
  const rawZ = Array.isArray(item.zutaten) ? item.zutaten : [];
  rawZ.forEach(z => {
    if(typeof z === 'string') selectedZutaten.set(z, '');
    else selectedZutaten.set(z.id, z.menge||'');
  });
  document.getElementById('ern-m-new-title').textContent='Lebensmittel bearbeiten';
  document.getElementById('ern-m-new-name').value=item.name;
  document.getElementById('ern-m-new-type').value=item.type;
  const sec=document.getElementById('ern-zutaten-section');
  if(sec){ sec.style.display=item.type==='gericht'?'block':'none'; }
  if(item.type==='gericht') renderZutatenChips();
  openModal('ern-m-new');
  setTimeout(()=>{setBewertung(item.bewertung);document.getElementById('ern-m-new-name').focus();},50);
}

function saveItem(){
  const name    = document.getElementById('ern-m-new-name').value.trim();
  const type    = document.getElementById('ern-m-new-type').value;
  const zutaten = type==='gericht'
    ? [...selectedZutaten.entries()].map(([id,menge])=>({id,menge}))
    : [];
  if(!name){showToast('Name fehlt');return}
  if(editCtx){
    const item=itemById(editCtx.itemId);
    if(item){item.name=name;item.type=type;item.zutaten=zutaten;item.bewertung=currentBewertung;}
    showToast(`${name} gespeichert ✓`);
  } else {
    bibliothek.push({id:uid(),name,type,zutaten,bewertung:currentBewertung});
    showToast(`${name} hinzugefügt`);
  }
  bibliothek.sort((a,b)=>a.name.localeCompare(b.name,'de'));
  editCtx=null; closeModal('ern-m-new'); render();
}

function deleteItem(itemId){
  const item=itemById(itemId);
  bibliothek=bibliothek.filter(x=>x.id!==itemId);
  showToast(`${item?.name} entfernt`);
  render();
}

// ── MOVE ENTRY ───────────────────────────

function openMoveModal(fromMealId, entryId, name){
  moveCtx = {fromMealId, entryId};
  document.getElementById('ern-m-move-sub').textContent = `"${name}"`;
  document.getElementById('ern-m-move-btns').innerHTML = MEALS
    .filter(m=>m.id !== fromMealId)
    .map(m=>`<button onclick="window.ern_confirmMove('${m.id}')"
      style="width:100%;padding:11px 14px;border-radius:10px;border:1px solid var(--border);
        background:var(--surface2);font-family:'JetBrains Mono',monospace;font-size:12px;
        color:var(--text);cursor:pointer;text-align:left;transition:all .15s"
      onmouseover="this.style.borderColor='var(--accent)'" 
      onmouseout="this.style.borderColor='var(--border)'">
      ${m.label}
    </button>`).join('');
  openModal('ern-m-move');
}

function confirmMove(toMealId){
  if(!moveCtx) return;
  const {fromMealId, entryId} = moveCtx;
  const idx = mealEntries[fromMealId].findIndex(e=>e.id===entryId);
  if(idx === -1) return;
  const [entry] = mealEntries[fromMealId].splice(idx, 1);
  mealEntries[toMealId].push(entry);
  // open destination meal
  Object.keys(mealOpen).forEach(k=>mealOpen[k]=false);
  mealOpen[toMealId] = true;
  moveCtx = null;
  closeModal('ern-m-move');
  render();
  const destLabel = MEALS.find(m=>m.id===toMealId)?.label;
  showToast(`${entry.name} → ${destLabel} ✓`);
}

// ── DELETE / EDIT MODE ────────────────────
function toggleDelMode(){
  delMode=!delMode;
  if(delMode){editMode=false;updateEditBtn();}
  const btn=document.getElementById('ern-btn-del');
  btn.classList.toggle('on',delMode);
  btn.textContent=delMode?'✓ Fertig':'🗑 Löschen';
  render();
}
function toggleEditMode(){
  editMode=!editMode;
  if(editMode){delMode=false;document.getElementById('ern-btn-del').classList.remove('on');document.getElementById('ern-btn-del').textContent='🗑 Löschen';}
  updateEditBtn();render();
}
function updateEditBtn(){
  const btn=document.getElementById('ern-btn-edit');
  btn.classList.toggle('on',editMode);
  btn.textContent=editMode?'✓ Fertig':'✎ Bearbeiten';
}

// ── MODALS ────────────────────────────────
function openModal(id){document.getElementById(id).classList.add('open')}
function closeModal(id){document.getElementById(id).classList.remove('open')}

// ── TOAST ─────────────────────────────────
let tt;
function showToast(msg){
  const el=document.getElementById('toast');
  el.textContent=msg;el.classList.add('show');
  clearTimeout(tt);tt=setTimeout(()=>el.classList.remove('show'),2200);
}
// Exports
window.ern_lpAction=function(btn){setTimeout(function(){if(window._lpFired!==undefined)window._lpFired=false;},50);if(typeof openAddModal==='function')openAddModal(btn.dataset.iid);};
window.ern_lpEntryAction=function(el){if(typeof openMoveModal==='function')openMoveModal(el.dataset.meal,el.dataset.entry,el.dataset.name);};
  window.ern_confirmMove = confirmMove;
  window.ern_deleteEntry = deleteEntry;
  window.ern_deleteItem = deleteItem;
  window.ern_deleteSpontan = deleteSpontan;
  window.ern_openEditItem = openEditItem;
  window.ern_pickMenge = pickMenge;
  window.ern_quickAdd = quickAdd;
  window.ern_saveComment = saveComment;
  window.ern_toggleComment = toggleComment;
  window.ern_toggleMeal = toggleMeal;
  window.ern_toggleSpItem = toggleSpItem;
  window.ern_toggleZutat = toggleZutat;
  window.ern_confirmAdd = confirmAdd;
  window.ern_cycleBewertung = cycleBewertung;
  window.ern_openNewItem = openNewItem;
  window.ern_openSpontanModal = openSpontanModal;
  window.ern_render = render;
  window.ern_toggleZutat = toggleZutat;
  window.ern_setZutatMenge = setZutatMenge;
  window.ern_saveItem = saveItem;
  window.ern_saveSpontan = saveSpontan;
  window.ern_toggleDelMode = toggleDelMode;
  window.ern_toggleEditMode = toggleEditMode;
  window.ern_toggleZutatenSection = toggleZutatenSection;
  window.ern_render = render;
  window.ern_toggleZutat = toggleZutat;
  window.ern_setZutatMenge = setZutatMenge;
})();

schmerz.js:
(function() {
const SCALE = [
  {v:0,label:'0',desc:'Kein Schmerz'},
  {v:1,label:'1',desc:'Kaum spürbar, ignorierbar'},
  {v:2,label:'2',desc:'Spürbar, stört kaum'},
  {v:3,label:'3',desc:'Deutlich, lenkt ab'},
  {v:4,label:'4',desc:'Stark, beeinträchtigt Alltagsfunktion'},
  {v:5,label:'5',desc:'Sehr stark, kaum funktionsfähig'},
];

const ALLODYNIE_DESC = 'Schmerz bei normalerweise schmerzlosen Reizen (Wasser, Berührung, leichter Druck)';

const ANKER = ['morgen','abend'];

// ── STATE ─────────────────────────────────
let regions = [
  {id:'ferse_l',  name:'Ferse links',    groups:['morgen','abend']},
  {id:'ferse_r',  name:'Ferse rechts',   groups:['morgen','abend']},
  {id:'nacken',   name:'Nacken',         groups:['morgen','abend']},
  {id:'schulter', name:'Schulter',       groups:['morgen','abend']},
  {id:'bauch',    name:'Bauch',          groups:['morgen','abend']},
  {id:'kopf',     name:'Kopf',           groups:['morgen','abend']},
];
regions.sort((a,b)=>a.name.localeCompare(b.name,'de'));

// ankerData: { morgen: { regionId: {val:0-5, nurAufstehen:bool} }, abend: {...} }
let ankerData = { morgen:{}, abend:{} };
let allodynie = { morgen:{}, abend:{} }; // {regionId: bool}
let ankerOpen = { morgen:true, abend:false };
let ankerComments = { morgen:'', abend:'' };
let ankerCommentOpen = { morgen:false, abend:false };
let spontanList = [];
let editRegionCtx = null;
let spontanVals = {};

function uid(){return Math.random().toString(36).slice(2,9)}
function escHtml(s){return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}
function nowTime(){
  const n=new Date();
  return `${String(n.getHours()).padStart(2,'0')}:${String(n.getMinutes()).padStart(2,'0')}`;
}

// ── RENDER ────────────────────────────────
function render(){
  ANKER.forEach(a=>{
    const body=document.getElementById('schmerz-body-'+a);
    const arr=document.getElementById('schmerz-arr-'+a);
    if(ankerOpen[a]){
      body.style.display='block'; arr.textContent='▲';
      renderRegions(a); renderCommentArea(a);
    } else {
      body.style.display='none'; arr.textContent='▼';
    }
    renderBadge(a);
  });
  renderSpontan();
}

function renderBadge(anker){
  const badge=document.getElementById('schmerz-badge-'+anker);
  const cbtn=document.getElementById('schmerz-cbtn-'+anker);
  const regs=regions.filter(r=>r.groups.includes(anker));
  const filled=regs.filter(r=>ankerData[anker][r.id]?.val!=null).length;
  const hasHigh=regs.some(r=>(ankerData[anker][r.id]?.val||0)>=3);
  if(filled===0){badge.textContent='—';badge.className='anker-badge'}
  else if(hasHigh){badge.textContent=`${filled}/${regs.length}`;badge.className='anker-badge active'}
  else{badge.textContent=`✓ ${filled}/${regs.length}`;badge.className='anker-badge done'}
  cbtn.classList.toggle('has-comment',!!ankerComments[anker]);
}


function toggleAllodynie(anker, regionId) {
  allodynie[anker][regionId] = !allodynie[anker][regionId];
  render();
}

function copyFromPrevDay(anker) {
  const yesterday = new Date();
  yesterday.setDate(yesterday.getDate() - 1);
  const yKey = 'schmerz_' + yesterday.toISOString().slice(0,10);
  try {
    const prev = JSON.parse(localStorage.getItem(yKey) || '{}');
    if(prev[anker] && Object.keys(prev[anker]).length > 0) {
      ankerData[anker] = Object.assign({}, prev[anker]);
      if(prev['allo_'+anker]) allodynie[anker] = Object.assign({}, prev['allo_'+anker]);
      render();
      showToast('Vortageswerte übernommen ✓');
    } else {
      showToast('Keine Vortageswerte vorhanden');
    }
  } catch(e) {
    showToast('Keine Vortageswerte vorhanden');
  }
}
function renderRegions(anker){
  const container=document.getElementById('schmerz-regions-'+anker);
  const regs=regions.filter(r=>r.groups.includes(anker));
  if(!regs.length){
    container.innerHTML=`<div style="font-size:11px;color:var(--muted);padding:4px 0">Keine Regionen konfiguriert</div>`;
    return;
  }
  container.innerHTML=regs.map(r=>{
    const entry=ankerData[anker][r.id]||{};
    const val=entry.val;
    const nurAufstehen=!!entry.nurAufstehen;
    const selDesc = val!=null && SCALE[val] ? SCALE[val].desc : '';
    const hasAllodynie = allodynie[anker][r.id] || false;
    const chips=SCALE.map(s=>`
      <button class="sv${val===s.v?' sel-'+s.v:''}"
        onclick="window.schmerz_setRegion('${anker}','${r.id}',${s.v})">
        <span class="sv-n">${s.label}</span>
      </button>`).join('');

    const valClass=val==null?'':val===0?'v0':val<=2?'v1':'v3';

    // "Nur beim Aufstehen" toggle — always visible in morgen, not just when val>0
    const aufstehBtn = anker==='morgen' ? `
      <button class="aufsteh-toggle${nurAufstehen?' on':''}"
        onclick="window.schmerz_toggleAufstehen('${anker}','${r.id}')">
        🦶 Nur beim Aufstehen
      </button>` : '';

    return `
      <div class="region-row">
        <div class="region-header">
          <span class="region-name">${r.name}</span>
          <div style="display:flex;align-items:center;gap:6px">
            ${aufstehBtn}
            ${val!=null?`<span class="region-val ${valClass}">${val}</span>`:''}
          </div>
        </div>
        <div class='scale-row'>${chips}</div>
        ${selDesc?`<div style='font-size:10px;color:var(--muted);margin-top:3px;padding:0 2px'>${selDesc}</div>`:''}
        <div style="margin-top:8px;padding-top:6px;border-top:1px solid var(--border)">
          <button onclick="window.schmerz_toggleAllodynie('${anker}','${r.id}')"
            style="width:100%;text-align:left;font-size:11px;padding:5px 8px;border-radius:7px;border:1px solid ${hasAllodynie?'var(--delete)':'var(--border)'};background:${hasAllodynie?'color-mix(in srgb,var(--delete) 10%,var(--surface))':'var(--surface)'};color:${hasAllodynie?'var(--delete)':'var(--muted)'};cursor:pointer;font-family:'JetBrains Mono',monospace">
            ${hasAllodynie?'🔴':'⚪'} Allodynie ${hasAllodynie?'(aktiv — Schmerz bei Berührung/Wasser/Druck)':'— tippen zum aktivieren'}
          </button>
        </div>
      </div>`;
  }).join('');
}

function renderCommentArea(anker){
  const container=document.getElementById('schmerz-comment-area-'+anker);
  const isOpen=ankerCommentOpen[anker];
  const comment=ankerComments[anker];
  if(isOpen){
    container.innerHTML=`
      <textarea class="comment-textarea" id="ta-${anker}"
        placeholder="Kommentar...">${comment}</textarea>
      <div class="comment-actions">
        <button class="comment-clear" onclick="document.getElementById('ta-${anker}').value=''">Leeren</button>
        <button class="comment-save" onclick="window.schmerz_saveComment('${anker}')">Speichern</button>
      </div>`;
    setTimeout(()=>{const ta=document.getElementById('schmerz-ta-'+anker);if(ta){ta.focus();ta.setSelectionRange(ta.value.length,ta.value.length)}},50);
  } else if(comment){
    container.innerHTML=`<div class="comment-preview" onclick="window.schmerz_toggleComment('${anker}')">${escHtml(comment)}</div>`;
  } else {
    container.innerHTML='';
  }
}

function renderSpontan(){
  const el=document.getElementById('schmerz-spontan-list');
  if(!spontanList.length){el.innerHTML='';return}
  el.innerHTML=spontanList.map(e=>`
    <div class="spontan-entry">
      <div class="spontan-time">${e.time}${e.note?' · '+e.note:''}</div>
      <div style="display:flex;flex-wrap:wrap">
        ${Object.entries(e.values).map(([rid,val])=>{
          const r=regions.find(x=>x.id===rid);
          const cls=val===0?'rp-0':val<=2?'rp-12':'rp-345';
          return `<span class="region-pill ${cls}">${r?.name||rid}: ${val}</span>`;
        }).join('')}
      </div>
      <button class="spontan-del" onclick="window.schmerz_delSpontan('${e.id}')">✕</button>
    </div>`).join('');
}

// ── INTERACTIONS ──────────────────────────
function toggleAnker(id){ankerOpen[id]=!ankerOpen[id];render()}

function setRegion(anker,regionId,val){
  if(!ankerData[anker][regionId]) ankerData[anker][regionId]={};
  if(ankerData[anker][regionId].val===val) ankerData[anker][regionId]={};
  else ankerData[anker][regionId].val=val;
  renderRegions(anker);
  renderBadge(anker);
}

function toggleAufstehen(anker,regionId){
  if(!ankerData[anker][regionId]) return;
  ankerData[anker][regionId].nurAufstehen=!ankerData[anker][regionId].nurAufstehen;
  renderRegions(anker);
}

// ── COMMENTS ─────────────────────────────
function toggleComment(anker){
  ankerCommentOpen[anker]=!ankerCommentOpen[anker];
  if(ankerCommentOpen[anker]) ankerOpen[anker]=true;
  render();
}
function saveComment(anker){
  const ta=document.getElementById('schmerz-ta-'+anker);
  ankerComments[anker]=ta?ta.value.trim():'';
  ankerCommentOpen[anker]=false;
  showToast(ankerComments[anker]?'Kommentar gespeichert ✓':'Kommentar entfernt');
  render();
}

// ── REGION MANAGER ────────────────────────
function openRegionMgr(){renderMgrChips();openModal('schmerz-m-mgr')}
function renderMgrChips(){
  document.getElementById('schmerz-mgr-chips').innerHTML=regions.map(r=>`
    <div style="display:inline-flex;align-items:center;gap:6px;border-radius:20px;
      padding:5px 10px;border:1px solid var(--border);background:var(--surface2);
      font-family:'JetBrains Mono',monospace;font-size:11px">
      ${r.name}
      <span style="font-size:9px;color:var(--muted)">${r.groups.join('/')}</span>
      <button onclick="window.schmerz_openEditRegion('${r.id}')"
        style="background:none;border:1px solid var(--accent3);border-radius:10px;
          padding:1px 7px;font-size:9px;color:var(--accent3);cursor:pointer">✎</button>
      <button onclick="window.schmerz_deleteRegion('${r.id}')"
        style="background:none;border:1px solid var(--delete);border-radius:10px;
          padding:1px 7px;font-size:9px;color:var(--delete);cursor:pointer">✕</button>
    </div>`).join('');
}

function openNewRegion(){
  editRegionCtx=null;
  document.getElementById('schmerz-m-region-title').textContent='Region anlegen';
  document.getElementById('schmerz-m-region-name').value='';
  document.querySelectorAll('#schmerz-m-region-grps .grp-btn').forEach(b=>b.classList.add('sel'));
  openModal('schmerz-m-region');
  setTimeout(()=>document.getElementById('schmerz-m-region-name').focus(),100);
}

function openEditRegion(rid){
  const r=regions.find(x=>x.id===rid);
  if(!r)return;
  editRegionCtx={rid};
  document.getElementById('schmerz-m-region-title').textContent='Region bearbeiten';
  document.getElementById('schmerz-m-region-name').value=r.name;
  document.querySelectorAll('#schmerz-m-region-grps .grp-btn').forEach(b=>
    b.classList.toggle('sel',r.groups.includes(b.dataset.g)));
  openModal('schmerz-m-region');
  setTimeout(()=>document.getElementById('schmerz-m-region-name').focus(),100);
}

function saveRegion(){
  const name=document.getElementById('schmerz-m-region-name').value.trim();
  const groups=[...document.querySelectorAll('#schmerz-m-region-grps .grp-btn.sel')].map(b=>b.dataset.g);
  if(!name){showToast('Name fehlt');return}
  if(!groups.length){showToast('Mindestens einen Block wählen');return}
  if(editRegionCtx){
    const r=regions.find(x=>x.id===editRegionCtx.rid);
    if(r){r.name=name;r.groups=groups;}
    showToast(`${name} gespeichert ✓`);
  } else {
    if(regions.find(r=>r.name.toLowerCase()===name.toLowerCase())){showToast('Bereits vorhanden');return}
    regions.push({id:uid(),name,groups});
    regions.sort((a,b)=>a.name.localeCompare(b.name,'de'));
    showToast(`${name} hinzugefügt`);
  }
  editRegionCtx=null;closeModal('schmerz-m-region');render();
}

function deleteRegion(rid){
  const r=regions.find(x=>x.id===rid);
  regions=regions.filter(x=>x.id!==rid);
  ANKER.forEach(a=>delete ankerData[a][rid]);
  showToast(`${r?.name} entfernt`);
  renderMgrChips();render();
}

// ── SPONTAN ───────────────────────────────
function openSpontan(){
  spontanVals={};
  document.getElementById('schmerz-m-spontan-time').value=nowTime();
  document.getElementById('schmerz-m-spontan-note').value='';
  renderSpontanRegions();
  openModal('schmerz-m-spontan');
}

function renderSpontanRegions(){
  document.getElementById('schmerz-m-spontan-regions').innerHTML=regions.map(r=>`
    <div class="region-row">
      <div class="region-header">
        <span class="region-name">${r.name}</span>
        ${spontanVals[r.id]!=null?`<span class="region-val">${spontanVals[r.id]}</span>`:''}
      </div>
      <div class="scale-row">${SCALE.map(s=>`
        <button class="sv${spontanVals[r.id]===s.v?' sel-'+s.v:''}"
          onclick="window.schmerz_setSpontanRegion('${r.id}',${s.v},this)">
          <span class="sv-n">${s.label}</span>
        </button>`).join('')}
      </div>
    </div>`).join('');
}

function setSpontanRegion(rid,val,btn){
  if(spontanVals[rid]===val) delete spontanVals[rid];
  else spontanVals[rid]=val;
  btn.closest('.scale-row').querySelectorAll('.sv').forEach((b,i)=>{
    b.className='sv'+(spontanVals[rid]===i?' sel-'+i:'');
  });
  const hdr=btn.closest('.region-row').querySelector('.region-header');
  let vspan=hdr.querySelector('.region-val');
  if(spontanVals[rid]!=null){
    if(!vspan){vspan=document.createElement('span');vspan.className='region-val';hdr.appendChild(vspan)}
    vspan.textContent=`${spontanVals[rid]}`;
  } else if(vspan) vspan.remove();
}

function saveSpontan(){
  const time=document.getElementById('schmerz-m-spontan-time').value||nowTime();
  const note=document.getElementById('schmerz-m-spontan-note').value.trim();
  if(!Object.keys(spontanVals).length){showToast('Mindestens eine Region wählen');return}
  spontanList.push({id:uid(),time,note,values:{...spontanVals}});
  spontanList.sort((a,b)=>a.time.localeCompare(b.time));
  closeModal('schmerz-m-spontan');render();
  showToast(`Schmerz ${time} erfasst ✓`);
}

function delSpontan(id){spontanList=spontanList.filter(e=>e.id!==id);render()}

// ── MODALS ────────────────────────────────
function openModal(id){document.getElementById(id).classList.add('open')}
function closeModal(id){document.getElementById(id).classList.remove('open')}

// ── TOAST ─────────────────────────────────
let tt;
function showToast(msg){
  const el=document.getElementById('toast');
  el.textContent=msg;el.classList.add('show');
  clearTimeout(tt);tt=setTimeout(()=>el.classList.remove('show'),2200);
}
// Exports
  window.schmerz_delSpontan = delSpontan;
  window.schmerz_deleteRegion = deleteRegion;
  window.schmerz_openEditRegion = openEditRegion;
  window.schmerz_saveComment = saveComment;
  window.schmerz_setRegion = setRegion;
  window.schmerz_setSpontanRegion = setSpontanRegion;
  window.schmerz_toggleAufstehen = toggleAufstehen;
  window.schmerz_openNewRegion = openNewRegion;
  window.schmerz_openRegionMgr = openRegionMgr;
  window.schmerz_openSpontan = openSpontan;
  window.schmerz_render = render;
  window.schmerz_toggleAllodynie = toggleAllodynie;
  window.schmerz_copyFromPrevDay = copyFromPrevDay;
  window.schmerz_saveRegion = saveRegion;
  window.schmerz_saveSpontan = saveSpontan;
  window.schmerz_toggleAnker = toggleAnker;
  window.schmerz_toggleComment = toggleComment;
  window.schmerz_render = render;
  window.schmerz_toggleAllodynie = toggleAllodynie;
  window.schmerz_copyFromPrevDay = copyFromPrevDay;
})();

