(function() {
// ── BRISTOL DATA ──────────────────────────
const BRISTOL_STEPS = [1, 1.5, 2, 2.5, 3, 3.5, 4, 4.5, 5, 5.5, 6, 6.5, 7];

const BRISTOL_LABELS = {
  '1':'Klümpchen','1.5':'Zw. 1–2','2':'Klumpig','2.5':'Zw. 2–3',
  '3':'Rissig','3.5':'Zw. 3–4','4':'Ideal ✓','4.5':'Zw. 4–5',
  '5':'Weich','5.5':'Zw. 5–6','6':'Breiig','6.5':'Zw. 6–7','7':'Wässrig'
};

const BRISTOL_INFO = {
  '1': {label:'Typ 1 – Klümpchen',
    desc:'Einzelne harte Klümpchen, wie Nüsse. Sehr schwer abzusetzen. Hinweis auf starke Verstopfung, zu wenig Flüssigkeit oder Ballaststoffe.'},
  '1.5':{label:'Typ 1.5',
    desc:'Zwischen Typ 1 und 2. Harte Klümpchen die leicht zusammenhängen. Stuhl kommt nur schwer heraus.'},
  '2': {label:'Typ 2 – Klumpig',
    desc:'Wurstförmig mit klumpiger Oberfläche. Schwer abzusetzen. Zeigt noch leichte Verstopfung an.'},
  '2.5':{label:'Typ 2.5',
    desc:'Zwischen Typ 2 und 3. Oberfläche weniger klumpig, aber noch nicht glatt. Übergangsform.'},
  '3': {label:'Typ 3 – Rissig',
    desc:'Wurstförmig mit rissiger Oberfläche. Etwas trocken aber normal. Leicht abzusetzen.'},
  '3.5':{label:'Typ 3.5',
    desc:'Zwischen Typ 3 und 4. Oberfläche leicht rissig, Form gut. Nahezu ideal.'},
  '4': {label:'Typ 4 – Ideal ✓',
    desc:'Glatte, weiche Wurst. Leicht abzusetzen ohne Pressen. Optimale Form – Zieldarm.'},
  '4.5':{label:'Typ 4.5',
    desc:'Zwischen Typ 4 und 5. Etwas weicher als ideal aber noch gut geformt. Vollkommen i.O.'},
  '5': {label:'Typ 5 – Weich',
    desc:'Weiche Klümpchen mit klar definierten Rändern. Leicht abzusetzen. Grenzwertig weich, aber noch akzeptabel.'},
  '5.5':{label:'Typ 5.5',
    desc:'Zwischen Typ 5 und 6. Klümpchen verlieren Form. Möglicherweise etwas zu hastig verdaut.'},
  '6': {label:'Typ 6 – Breiig',
    desc:'Flockig, breiig mit zerfransten Rändern. Deutlich zu weich. Kann auf Entzündung, Stress oder Unverträglichkeit hinweisen.'},
  '6.5':{label:'Typ 6.5',
    desc:'Zwischen Typ 6 und 7. Fast flüssig mit erkennbaren Stücken. Stark erhöhte Darmpassage.'},
  '7': {label:'Typ 7 – Wässrig',
    desc:'Vollständig flüssig, keine festen Stücke. Durchfall. Auf Flüssigkeits- und Elektrolytzufuhr achten. Bei Anhaltung Arzt aufsuchen.'}
};

const BRISTOL_COLORS = {
  1:'var(--red)', 2:'var(--delete)', 3:'var(--gold)',
  4:'var(--accent2)', 5:'var(--gold)', 6:'var(--delete)', 7:'var(--red)'
};

function bristolColor(v){ return BRISTOL_COLORS[Math.ceil(v)] || 'var(--muted)'; }
function bristolBase(v){ return Math.ceil(v); }

// ── STATE ─────────────────────────────────
// entries: [{id, time, bristol, infoOpen}]
let entries = [];
let infoOpen = {}; // entryId -> bool

function uid(){ return Math.random().toString(36).slice(2,9); }
function nowTime(){
  const n=new Date();
  return `${String(n.getHours()).padStart(2,'0')}:${String(n.getMinutes()).padStart(2,'0')}`;
}

// ── RENDER ────────────────────────────────
function render(){
  renderEntries();
}

function renderEntries(){
  const el = document.getElementById('stuhl-entries-list');
  if(!entries.length){ el.innerHTML=''; return; }

  el.innerHTML = entries.sort((a,b)=>a.time.localeCompare(b.time)).map(e=>{
    const b = e.bristol;
    const color = bristolColor(b);
    const label = BRISTOL_LABELS[String(b)] || '';
    const info = BRISTOL_INFO[String(b)];
    const isInfoOpen = !!infoOpen[e.id];

    const scale = BRISTOL_STEPS.map(v=>{
      const isHalf = !Number.isInteger(v);
      const base = bristolBase(v);
      const active = v === b;
      return `<button class="bs-btn bs-${base}${isHalf?' bs-half':' bs-major'}${active?' active':''}"
        onclick="window.stuhl_setVal('${e.id}',${v})">
        ${isHalf ? '·' : v}
      </button>`;
    }).join('');

    return `<div class="entry-card" data-entry-id="${e.id}">
      <div class="entry-header">
        <span class="entry-time">${e.time}</span>
        <span class="entry-badge" style="background:${color}20;color:${color};border:1px solid ${color};border-radius:20px;padding:2px 8px;font-size:10px">Bristol ${b} · ${label}</span>
        <button class="entry-del" onclick="window.stuhl_deleteEntry('${e.id}')">✕</button>
      </div>
      <div class="bristol-scale">${scale}</div>
      <div class="info-pill" onclick="window.stuhl_toggleInfo('${e.id}')">
        <span style="font-size:10px;color:var(--muted)">${isInfoOpen?'▲ weniger':'▼ was bedeutet das?'}</span>
      </div>
      ${isInfoOpen?`<div class="info-desc" style="font-size:11px;color:var(--muted);padding:6px 0;line-height:1.5">${info?.desc||''}</div>`:''}
    </div>`;
  }).join('');
}

// ── INTERACTIONS ──────────────────────────
function addEntry(){
  // Create entry and open inline — show it immediately
  const id = uid();
  entries.push({ id:id, time:nowTime(), bristol:4 });
  render();
  // Scroll to and highlight the new entry
  setTimeout(function(){
    const el = document.querySelector('[data-entry-id="'+id+'"]');
    if(el) el.scrollIntoView({behavior:'smooth', block:'nearest'});
  }, 100);
}

function deleteEntry(id){
  entries = entries.filter(e=>e.id!==id);
  delete infoOpen[id];
  render();
}

function setVal(id, v){
  const e = entries.find(x=>x.id===id);
  if(e){ e.bristol=v; infoOpen[id]=true; renderEntries(); renderDbg(); }
}

function toggleInfo(id){
  infoOpen[id] = !infoOpen[id];
  renderEntries();
}

// ── LEGENDE ───────────────────────────────
function openLegend(){
  document.getElementById('stuhl-legend-items').innerHTML =
    Object.entries(BRISTOL_INFO).map(([v, info])=>{
      const c = bristolColor(parseFloat(v));
      const isMain = Number.isInteger(parseFloat(v));
      return `<div class="legend-item" style="border-color:color-mix(in srgb,${c} 30%,var(--border))">
        <div class="legend-item-val" style="color:${c}">${info.label}</div>
        <div class="legend-item-desc">${info.desc}</div>
      </div>`;
    }).join('');
  openModal('stuhl-m-legend');
}

// ── MODALS ────────────────────────────────
function openModal(id){document.getElementById(id).classList.add('open')}
function closeModal(id){document.getElementById(id).classList.remove('open')}

// ── TOAST ─────────────────────────────────
let tt;
function showToast(msg){
  const el=document.getElementById('toast');
  el.textContent=msg;el.classList.add('show');
  clearTimeout(tt);tt=setTimeout(()=>el.classList.remove('show'),2500);
}
// Exports
  window.stuhl_deleteEntry = deleteEntry;
  window.stuhl_setVal = setVal;
  window.stuhl_toggleInfo = toggleInfo;
  window.stuhl_addEntry = addEntry;
  window.stuhl_openLegend = openLegend;
  window.stuhl_render = render;
  window.stuhl_render = render;
})();

