(function() {
const DAUER_QUICK = [15,20,30,45,60,90];
let aktivitaeten = [];
// Leer — Aktivitäten selbst anlegen
let entries = [];
let addCtx = null, editCtx = null, currentInt = 'mittel';
let delMode = false, editMode = false;
let lpTimer = null, lpFired = false;
function uid(){return Math.random().toString(36).slice(2,9)}
function nowTime(){const n=new Date();return`${String(n.getHours()).padStart(2,'0')}:${String(n.getMinutes()).padStart(2,'0')}`}

function setInt(v,btn){
  currentInt=v;
  document.querySelectorAll('#akt-m-add-int .int-btn').forEach(b=>b.className='int-btn');
  btn.className=`int-btn sel-${v}`;
}

function render(){
  // entries
  const el=document.getElementById('akt-entries');
  if(!entries.length){
    el.innerHTML='<div style="font-size:11px;color:var(--muted);font-style:italic;margin-bottom:10px">Noch nichts erfasst</div>';
  } else {
    const intColor={leicht:'var(--accent2)',mittel:'var(--gold)',intensiv:'var(--delete)'};
    el.innerHTML=[...entries].sort((a,b)=>a.time.localeCompare(b.time)).map(e=>`
      <div class="entry-card" data-eid="${e.id}">
        <div class="entry-header">
          <span style="font-size:14px">${e.icon}</span>
          <span style="font-size:11px;font-weight:500;flex:1;margin-left:6px">${e.name}</span>
          ${e.dauer?`<span style="font-size:10px;color:var(--gold)">${e.dauer} min</span>`:''}
          <span style="font-size:10px;color:${intColor[e.intensitaet]||'var(--muted)'};margin-left:8px">${e.intensitaet}</span>
          <span class="entry-time" style="margin-left:8px">${e.time}</span>
          <span style="font-size:9px;color:var(--muted);margin-left:4px">⋯</span>
        <button class="entry-del" onclick="window.akt_deleteEntry('${e.id}')">✕</button>
        </div>
      </div>`).join('');
  }
  // chips
  const cc=document.getElementById('akt-act-chips');
  if(!aktivitaeten.length && !delMode && !editMode){
    cc.innerHTML=`<div style="font-size:11px;color:var(--muted);font-style:italic;margin-bottom:8px">Noch keine Aktivitäten</div><button class="act-chip" onclick="window.akt_openNew()" style="border-style:dashed;flex-direction:row;align-items:center">+</button>`;
    return;
  }
  cc.innerHTML=aktivitaeten.map(a=>{
    if(delMode) return `<div class="act-chip" style="border-color:var(--delete);flex-direction:row;align-items:center;gap:6px">
      <span style="flex:1">${a.icon} ${a.name}</span>
      <button class="chip-del-btn" onclick="window.akt_deleteAkt('${a.id}')">✕</button>
    </div>`;
    if(editMode) return `<div class="act-chip" style="border-color:var(--accent3);flex-direction:row;align-items:center;gap:6px">
      <span style="flex:1">${a.icon} ${a.name}</span>
      <button class="chip-edit-btn" onclick="window.akt_openEdit('${a.id}')">✎</button>
    </div>`;
    return `<button class="act-chip" onclick="window.akt_quickAdd('${a.id}')">${a.icon} ${a.name}</button>`;
  }).join('')+(!delMode&&!editMode?`<button class="act-chip" onclick="window.akt_openNew()" style="border-style:dashed">+</button>`:'');
}

// ── LONG PRESS ON ENTRY ──────────────────
let entryLpTimer=null, entryLpFired=false;

function openEditEntry(eid){
  const entry=entries.find(x=>x.id===eid);if(!entry)return;
  addCtx={editId:eid};
  document.getElementById('akt-m-add-title').textContent=`✎ ${entry.icon} ${entry.name} bearbeiten`;
  document.getElementById('akt-m-add-type').innerHTML=aktivitaeten.map(a=>`<option value="${a.id}"${a.id===entry.aid?' selected':''}>${a.icon} ${a.name}</option>`).join('');
  document.getElementById('akt-m-add-dauer').value=entry.dauer||'';
  document.getElementById('akt-m-add-time').value=entry.time;
  document.getElementById('akt-m-add-quick').innerHTML=[15,20,30,45,60,90].map(v=>`<button class="db${entry.dauer===v?' sel':''}" onclick="window.akt_pickDauer(${v},this)">${v} min</button>`).join('');
  // set intensity
  currentInt=entry.intensitaet||'mittel';
  document.querySelectorAll('#akt-m-add-int .int-btn').forEach(b=>{b.className='int-btn';if(b.onclick.toString().includes(currentInt))b.className=`int-btn sel-${currentInt}`;});
  openModal('akt-m-add');
}

function quickAdd(aid){
  openAddModal(aid);
}

function openAddModal(aid){
  if(!aktivitaeten.length){showToast('Erst eine Aktivität anlegen →  + Neu');return;}
  const a=aktivitaeten.find(x=>x.id===aid)||aktivitaeten[0];
  addCtx={aid:a.id};
  document.getElementById('akt-m-add-title').textContent=`${a.icon} ${a.name}`;
  document.getElementById('akt-m-add-time').value=nowTime();
  document.getElementById('akt-m-add-dauer').value='';
  document.getElementById('akt-m-add-type').innerHTML=aktivitaeten.map(x=>`<option value="${x.id}"${x.id===aid?' selected':''}>${x.icon} ${x.name}</option>`).join('');
  document.getElementById('akt-m-add-quick').innerHTML=DAUER_QUICK.map(v=>`<button class="db" onclick="window.akt_pickDauer(${v},this)">${v} min</button>`).join('');
  setInt('mittel',document.querySelectorAll('#akt-m-add-int .int-btn')[1]);
  openModal('akt-m-add');
}
function pickDauer(v,btn){
  document.getElementById('akt-m-add-dauer').value=v;
  btn.closest('.dauer-row').querySelectorAll('.db').forEach(b=>b.classList.remove('sel'));
  btn.classList.add('sel');
}
function confirmAdd(){
  const aid=document.getElementById('akt-m-add-type').value;
  const a=aktivitaeten.find(x=>x.id===aid);if(!a)return;
  const dauer=parseInt(document.getElementById('akt-m-add-dauer').value)||null;
  if(!dauer){showToast('Bitte Dauer eingeben');document.getElementById('akt-m-add-dauer').focus();return;}
  const time=document.getElementById('akt-m-add-time').value||nowTime();
  if(addCtx?.editId){
    const idx=entries.findIndex(x=>x.id===addCtx.editId);
    if(idx!==-1){entries[idx]={...entries[idx],aid:a.id,name:a.name,icon:a.icon,dauer,intensitaet:currentInt,time};}
    closeModal('akt-m-add');addCtx=null;render();
    showToast(`${a.icon} ${a.name} aktualisiert ✓`);
  } else {
    entries.push({id:uid(),aid,name:a.name,icon:a.icon,dauer,intensitaet:currentInt,time});
    closeModal('akt-m-add');addCtx=null;render();
    showToast(`${a.icon} ${a.name} · ${dauer} min ✓`);
  }
}
function deleteEntry(id){entries=entries.filter(e=>e.id!==id);render();}
function toggleDelMode(){
  delMode=!delMode;
  if(delMode)editMode=false;
  updateModeBtns();render();
}
function toggleEditMode(){
  editMode=!editMode;
  if(editMode)delMode=false;
  updateModeBtns();render();
}
function updateModeBtns(){
  const d=document.getElementById('akt-btn-del');
  d.classList.toggle('on',delMode);d.textContent=delMode?'✓ Fertig':'🗑 Löschen';
  const e=document.getElementById('akt-btn-edit');
  e.classList.toggle('on',editMode);e.textContent=editMode?'✓ Fertig':'✎ Bearbeiten';
}
function openEdit(id){
  editCtx={id};
  const a=aktivitaeten.find(x=>x.id===id);if(!a)return;
  document.getElementById('akt-m-new-title').textContent='Aktivität bearbeiten';
  document.getElementById('akt-m-new-name').value=a.name;
  document.getElementById('akt-m-new-icon').value='';
  document.getElementById('akt-selected-icon-preview').textContent=a.icon;
  document.querySelectorAll('#akt-icon-picker .icon-opt').forEach(b=>b.classList.toggle('sel',b.textContent===a.icon));
  openModal('akt-m-new');
  setTimeout(()=>document.getElementById('akt-m-new-name').focus(),50);
}
function selectIcon(icon,btn){
  document.getElementById('akt-selected-icon-preview').textContent=icon;
  document.getElementById('akt-m-new-icon').value='';
  document.querySelectorAll('#akt-icon-picker .icon-opt').forEach(b=>b.classList.remove('sel'));
  btn.classList.add('sel');
}
function updateIconPreview(){
  const v=document.getElementById('akt-m-new-icon').value.trim();
  if(v){
    document.getElementById('akt-selected-icon-preview').textContent=v;
    document.querySelectorAll('#akt-icon-picker .icon-opt').forEach(b=>b.classList.remove('sel'));
  }
}
function deleteAkt(id){aktivitaeten=aktivitaeten.filter(x=>x.id!==id);render();}
function openNew(){
  editCtx=null;
  document.getElementById('akt-m-new-title').textContent='Aktivität anlegen';
  document.getElementById('akt-m-new-name').value='';
  document.getElementById('akt-m-new-icon').value='';
  document.getElementById('akt-selected-icon-preview').textContent='🏅';
  document.querySelectorAll('#akt-icon-picker .icon-opt').forEach(b=>b.classList.remove('sel'));
  openModal('akt-m-new');
  setTimeout(()=>document.getElementById('akt-m-new-name').focus(),50);
}
function saveNew(){
  const name=document.getElementById('akt-m-new-name').value.trim();
  const icon=document.getElementById('akt-selected-icon-preview')?.textContent||document.getElementById('akt-m-new-icon').value.trim()||'🏅';
  if(!name){showToast('Name fehlt');return;}
  if(editCtx?.id){
    const a=aktivitaeten.find(x=>x.id===editCtx.id);
    if(a){a.name=name;a.icon=icon;}
    showToast(`${icon} ${name} gespeichert ✓`);
  } else {
    aktivitaeten.push({id:uid(),name,icon});
    aktivitaeten.sort((a,b)=>a.name.localeCompare(b.name,'de'));
    showToast(`${icon} ${name} hinzugefügt`);
  }
  editCtx=null;
  closeModal('akt-m-new');render();
}
function openModal(id){document.getElementById(id).classList.add('open')}
function closeModal(id){document.getElementById(id).classList.remove('open')}
// modal listeners: global
let tt;
function showToast(msg){const el=document.getElementById('toast');el.textContent=msg;el.classList.add('show');clearTimeout(tt);tt=setTimeout(()=>el.classList.remove('show'),2200);}
// Exports
window.akt_lpAction=function(card){if(typeof openEditEntry==='function')openEditEntry(card.dataset.eid);};
  window.akt_deleteAkt = deleteAkt;
  window.akt_deleteEntry = deleteEntry;
  window.akt_openEdit = openEdit;
  window.akt_openNew = openNew;
  window.akt_pickDauer = pickDauer;
  window.akt_quickAdd = quickAdd;
  window.akt_confirmAdd = confirmAdd;
  window.akt_render = render;
  window.akt_saveNew = saveNew;
  window.akt_selectIcon = selectIcon;
  window.akt_setInt = setInt;
  window.akt_toggleDelMode = toggleDelMode;
  window.akt_toggleEditMode = toggleEditMode;
  window.akt_updateIconPreview = updateIconPreview;
  window.akt_render = render;
})();

regen.js:
(function() {
const DAUER_QUICK=[5,10,15,20,30,45,60];
let regenItems=[
  {id:'kalt', name:'Kalt duschen', icon:'🧊'},
  {id:'rlt',  name:'RLT',          icon:'🔴'},
  {id:'nsdr', name:'NSDR',         icon:'🧘'},
  {id:'medi', name:'Meditation',   icon:'🙏'},
  {id:'neur', name:'Nurosym',      icon:'⚡'},
  {id:'atem', name:'Atemübungen',  icon:'💨'},
];
regenItems.sort((a,b)=>a.name.localeCompare(b.name,'de'));
let entries=[];
let delMode=false,editMode=false,addCtx=null,editCtx=null;
function uid(){return Math.random().toString(36).slice(2,9)}
function nowTime(){const n=new Date();return`${String(n.getHours()).padStart(2,'0')}:${String(n.getMinutes()).padStart(2,'0')}`}

function render(){
  // entries list
  const el=document.getElementById('regen-entries');
  if(el){
    if(!entries.length){
      el.innerHTML='<div style="font-size:11px;color:var(--muted);font-style:italic;margin-bottom:10px">Noch nichts erfasst</div>';
    } else {
      el.innerHTML=[...entries].sort((a,b)=>a.time.localeCompare(b.time)).map(e=>`
        <div class="entry-card" data-eid="${e.id}">
          <div class="entry-header">
            <span style="font-size:14px">${e.icon}</span>
            <span style="font-size:11px;font-weight:500;flex:1;margin-left:6px">${e.name}</span>
            <span style="font-size:10px;color:var(--gold)">${e.dauer} min</span>
            <span class="entry-time" style="margin-left:8px">${e.time}</span>
            <span style="font-size:9px;color:var(--muted);margin-left:4px">⋯</span>
            <button class="entry-del" onclick="window.regen_deleteEntry('${e.id}')">✕</button>
          </div>
        </div>`).join('');
    }
  }
  // chips
  const cc=document.getElementById('regen-chips');
  cc.innerHTML=regenItems.map(item=>{
    if(delMode) return `<div class="regen-chip" style="border-color:var(--delete);flex-direction:row;align-items:center;gap:6px">
      <div style="flex:1">${item.icon} ${item.name}</div>
      <button class="chip-del-btn" onclick="window.regen_deleteItem('${item.id}')">✕</button>
    </div>`;
    if(editMode) return `<div class="regen-chip" style="border-color:var(--accent3);flex-direction:row;align-items:center;gap:6px">
      <div style="flex:1">${item.icon} ${item.name}</div>
      <button class="chip-edit-btn" onclick="window.regen_openEdit('${item.id}')">✎</button>
    </div>`;
    return `<button class="regen-chip" onclick="window.regen_openAddModal('${item.id}')">${item.icon} ${item.name}</button>`;
  }).join('')+(!delMode&&!editMode?`<button class="chip-add" onclick="window.regen_openNewItem()" style="display:inline-flex;align-items:center;border-radius:20px;padding:4px 10px;font-size:16px;border:1px dashed var(--border);color:var(--muted);cursor:pointer;background:none">+</button>`:'');
}

// ── ADD MODAL ─────────────────────────────
function openAddModal(rid){
  const item=regenItems.find(x=>x.id===rid);if(!item)return;
  addCtx={rid};
  document.getElementById('regen-m-dauer-title').textContent=`${item.icon} ${item.name}`;
  document.getElementById('regen-m-dauer-val').value='';
  document.getElementById('regen-m-dauer-quick').innerHTML=[5,10,15,20,30,45,60].map(v=>
    `<button class="db" onclick="window.regen_pickDauer(${v},this)">${v} min</button>`).join('');
  document.getElementById('regen-m-dauer-time').value=nowTime();
  openModal('regen-m-dauer');
  setTimeout(()=>document.getElementById('regen-m-dauer-val').focus(),100);
}
function pickDauer(v,btn){
  document.getElementById('regen-m-dauer-val').value=v;
  btn.closest('.dq').querySelectorAll('.db').forEach(b=>b.classList.remove('sel'));
  btn.classList.add('sel');
}
function confirmDauer(){
  const dauer=parseInt(document.getElementById('regen-m-dauer-val').value)||null;
  if(!dauer){showToast('Bitte Dauer eingeben');document.getElementById('regen-m-dauer-val').focus();return;}
  const time=document.getElementById('regen-m-dauer-time').value||nowTime();
  if(addCtx?.editId){
    const idx=entries.findIndex(x=>x.id===addCtx.editId);
    if(idx!==-1){entries[idx].dauer=dauer;entries[idx].time=time;}
    closeModal('regen-m-dauer');addCtx=null;render();showToast('Eintrag aktualisiert ✓');
  } else {
    const item=regenItems.find(x=>x.id===addCtx.rid);
    entries.push({id:uid(),rid:item.id,name:item.name,icon:item.icon,dauer,time});
    closeModal('regen-m-dauer');addCtx=null;render();
    showToast(`${item.icon} ${item.name} · ${dauer} min ✓`);
  }
}
function cancelDauer(){closeModal('regen-m-dauer');addCtx=null;}
function deleteEntry(id){entries=entries.filter(e=>e.id!==id);render();}

// ── LONG PRESS ON ENTRY ──────────────────
let entryLpTimer=null,entryLpFired=false;

function toggleDelMode(){delMode=!delMode;if(delMode)editMode=false;updateBtns();render();}
function toggleEditMode(){editMode=!editMode;if(editMode)delMode=false;updateBtns();render();}
function updateBtns(){
  const d=document.getElementById('regen-btn-del');d.classList.toggle('on',delMode);d.textContent=delMode?'✓ Fertig':'🗑 Löschen';
  const e=document.getElementById('regen-btn-edit');e.classList.toggle('on',editMode);e.textContent=editMode?'✓ Fertig':'✎ Bearbeiten';
}
function deleteItem(id){regenItems=regenItems.filter(x=>x.id!==id);render();}

function openNewItem(){openEditModal(null);}
function openEdit(id){openEditModal(id);}
function openEditModal(id){
  editCtx={id};
  const item=id?regenItems.find(x=>x.id===id):null;
  document.getElementById('regen-m-edit-title').textContent=item?'Bearbeiten':'Neu anlegen';
  document.getElementById('regen-m-edit-name').value=item?.name||'';
  document.getElementById('regen-m-edit-icon').value='';
  const icon=item?.icon||'🔋';
  document.getElementById('regen-icon-preview').textContent=icon;
  document.querySelectorAll('#regen-icon-picker .icon-opt').forEach(b=>b.classList.toggle('sel',b.textContent===icon));
  document.getElementById('regen-m-edit-dauer').value=item?.defaultDauer||'';
  document.getElementById('regen-m-edit-quick').innerHTML=DAUER_QUICK.map(v=>`<button class="db${(item?.defaultDauer||0)===v?' sel':''}" onclick="window.regen_pickEditDauer(${v},this)">${v} min</button>`).join('');
  openModal('regen-m-edit');setTimeout(()=>document.getElementById('regen-m-edit-name').focus(),50);
}
function selectRegenIcon(icon,btn){
  document.getElementById('regen-icon-preview').textContent=icon;
  document.getElementById('regen-m-edit-icon').value='';
  document.querySelectorAll('#regen-icon-picker .icon-opt').forEach(b=>b.classList.remove('sel'));
  btn.classList.add('sel');
}
function updateRegenIconPreview(){
  const v=document.getElementById('regen-m-edit-icon').value.trim();
  if(v){
    document.getElementById('regen-icon-preview').textContent=v;
    document.querySelectorAll('#regen-icon-picker .icon-opt').forEach(b=>b.classList.remove('sel'));
  }
}
function pickEditDauer(v,btn){document.getElementById('regen-m-edit-dauer').value=v;btn.closest('.dq').querySelectorAll('.db').forEach(b=>b.classList.remove('sel'));btn.classList.add('sel');}
function saveEdit(){
  const name=document.getElementById('regen-m-edit-name').value.trim();
  const icon=document.getElementById('regen-icon-preview')?.textContent||document.getElementById('regen-m-edit-icon').value.trim()||'🔋';
  const dauer=parseInt(document.getElementById('regen-m-edit-dauer').value)||null;
  if(!name){showToast('Name fehlt');return;}
  if(editCtx.id){
    const item=regenItems.find(x=>x.id===editCtx.id);
    if(item){item.name=name;item.icon=icon;item.defaultDauer=dauer;}
  } else {
    regenItems.push({id:uid(),name,icon,defaultDauer:dauer,doneToday:false,dauer:null});
    regenItems.sort((a,b)=>a.name.localeCompare(b.name,'de'));
  }
  editCtx=null;
  closeModal('regen-m-edit');render();showToast(`${icon} ${name} gespeichert ✓`);
}

function openModal(id){document.getElementById(id).classList.add('open')}
function closeModal(id){document.getElementById(id).classList.remove('open')}
// modal listeners: global
let tt;function showToast(msg){const el=document.getElementById('toast');el.textContent=msg;el.classList.add('show');clearTimeout(tt);tt=setTimeout(()=>el.classList.remove('show'),2200);}
// Exports
window.regen_lpAction=function(card){if(typeof entries==='undefined'||!entries)return;var e=entries.find(function(x){return x.id===card.dataset.eid;});if(!e)return;if(typeof addCtx!=='undefined')addCtx={rid:e.rid,editId:e.id};var item=(typeof regenItems!=='undefined'?regenItems:[]).find(function(x){return x.id===e.rid;})||{icon:e.icon||'',name:e.name||''};var t=document.getElementById('regen-m-dauer-title');if(t)t.textContent='Bearbeiten: '+item.icon+' '+item.name;var v=document.getElementById('regen-m-dauer-val');if(v)v.value=e.dauer||'';var tm=document.getElementById('regen-m-dauer-time');if(tm)tm.value=e.time||'';openModal('regen-m-dauer');};
  window.regen_deleteEntry = deleteEntry;
  window.regen_deleteItem = deleteItem;
  window.regen_openAddModal = openAddModal;
  window.regen_openEdit = openEdit;
  window.regen_openNewItem = openNewItem;
  window.regen_pickDauer = pickDauer;
  window.regen_pickEditDauer = pickEditDauer;
  window.regen_cancelDauer = cancelDauer;
  window.regen_confirmDauer = confirmDauer;
  window.regen_render = render;
  window.regen_saveEdit = saveEdit;
  window.regen_selectRegenIcon = selectRegenIcon;
  window.regen_toggleDelMode = toggleDelMode;
  window.regen_toggleEditMode = toggleEditMode;
  window.regen_updateRegenIconPreview = updateRegenIconPreview;
  window.regen_render = render;
})();

fam.js:
(function() {
// ── FAMILIE ───────────────────────────────
const FAM_ICONS = {harmonisch:'😌',neutral:'😐',angespannt:'😤'};
let famData = {morgen:{stimmung:null,kommentar:''},abend:{stimmung:null,kommentar:''}};
let famAnkerOpen = {morgen:true,abend:false};
let famCommentOpen = {morgen:false,abend:false};

function toggleAnker(id){famAnkerOpen[id]=!famAnkerOpen[id];renderFam();}

function setFamStimmung(anker,val,btn){
  famData[anker].stimmung = famData[anker].stimmung===val?null:val;
  const row=btn.closest('.stimmung-row');
  row.querySelectorAll('.stim-btn').forEach(b=>b.className='stim-btn');
  if(famData[anker].stimmung) btn.className=`stim-btn sel-${val}`;
  updateFamBadge(anker);renderDbg();
  if(famData[anker].stimmung) showToast(`Familie ${anker}: ${FAM_ICONS[val]} ${val}`);
}

function updateFamBadge(anker){
  const s=famData[anker].stimmung;
  document.getElementById('fam-badge-'+anker).textContent=s?FAM_ICONS[s]:'';
  document.getElementById('fam-cbtn-'+anker).classList.toggle('has-comment',!!famData[anker].kommentar);
}

function renderFam(){
  ['morgen','abend'].forEach(a=>{
    const body=document.getElementById('fam-body-'+a);
    const arr=document.getElementById('fam-arr-'+a);
    if(famAnkerOpen[a]){body.style.display='block';arr.textContent='▲';}
    else{body.style.display='none';arr.textContent='▼';}
    updateFamBadge(a);
    renderFamComment(a);
  });
}

function toggleFamComment(anker){
  famCommentOpen[anker]=!famCommentOpen[anker];
  if(famCommentOpen[anker]) famAnkerOpen[anker]=true;
  renderFam();
}
function renderFamComment(anker){
  const container=document.getElementById('fam-comment-area-'+anker);
  if(!container)return;
  const isOpen=famCommentOpen[anker];
  const comment=famData[anker].kommentar;
  if(isOpen){
    container.innerHTML=`<textarea class="comment-textarea" id="ta-fam-${anker}" placeholder="Kommentar...">${comment}</textarea>
      <div class="comment-actions">
        <button class="comment-clear" onclick="document.getElementById('ta-fam-${anker}').value=''">Leeren</button>
        <button class="comment-save" onclick="window.fam_saveFamComment('${anker}')">Speichern</button>
      </div>`;
    setTimeout(()=>{const ta=document.getElementById('ta-fam-'+anker);if(ta){ta.focus();ta.setSelectionRange(ta.value.length,ta.value.length)}},50);
  } else if(comment){
    container.innerHTML=`<div class="comment-preview" onclick="window.fam_toggleFamComment('${anker}')">${comment}</div>`;
  } else container.innerHTML='';
}
function saveFamComment(anker){
  const ta=document.getElementById('ta-fam-'+anker);
  famData[anker].kommentar=ta?ta.value.trim():'';
  famCommentOpen[anker]=false;
  showToast(famData[anker].kommentar?'Kommentar gespeichert ✓':'Kommentar entfernt');
  renderFam();renderDbg();
}

// ── SOZIALE KONTAKTE ──────────────────────
const TYPE_ICONS = {telefon:'📞',nachricht:'💬',treffen:'🤝'};
let kontakte = [];
let currentKontaktType = 'treffen';
let currentKontaktQual = 'gut';

function uid(){return Math.random().toString(36).slice(2,9)}

function setKontaktType(v,btn){
  currentKontaktType=v;
  document.querySelectorAll('#fam-kontakt-type-row .type-btn').forEach(b=>b.classList.remove('sel'));
  btn.classList.add('sel');
}
function setKontaktQual(v,btn){
  currentKontaktQual=v;
  document.querySelectorAll('#fam-kontakt-qual-row .qual-btn').forEach(b=>b.className='qual-btn');
  btn.className=`qual-btn sel-${v}`;
}

// ── LONG PRESS ON KONTAKT ────────────────
let kontaktLpTimer=null, kontaktLpFired=false;

let editKontaktCtx=null;

function openEditKontakt(id){
  const k=kontakte.find(x=>x.id===id);if(!k)return;
  editKontaktCtx={id};
  setKontaktType(k.type, document.querySelector(`#kontakt-type-row .type-btn:nth-child(${k.type==='telefon'?1:k.type==='nachricht'?2:3})`));
  setKontaktQual(k.qualitaet, document.querySelector(`#kontakt-qual-row .qual-btn:nth-child(${k.qualitaet==='oberflächlich'?1:k.qualitaet==='gut'?2:3})`));
  document.getElementById('fam-kontakt-person').value=k.person||'';
  openModal('fam-m-kontakt');
  setTimeout(()=>document.getElementById('fam-kontakt-person').focus(),50);
}

function openAddKontakt(){
  editKontaktCtx=null;
  currentKontaktType='treffen';currentKontaktQual='gut';
  document.getElementById('fam-kontakt-person').value='';
  document.querySelectorAll('#fam-kontakt-type-row .type-btn').forEach((b,i)=>b.classList.toggle('sel',i===2));
  document.querySelectorAll('#fam-kontakt-qual-row .qual-btn').forEach((b,i)=>{b.className='qual-btn';if(i===1)b.className='qual-btn sel-gut';});
  openModal('fam-m-kontakt');
  setTimeout(()=>document.getElementById('fam-kontakt-person').focus(),50);
}

function saveKontakt(){
  const person=document.getElementById('fam-kontakt-person').value.trim();
  if(editKontaktCtx){
    const k=kontakte.find(x=>x.id===editKontaktCtx.id);
    if(k){k.type=currentKontaktType;k.qualitaet=currentKontaktQual;k.person=person||undefined;}
    editKontaktCtx=null;
    closeModal('fam-m-kontakt');renderSozial();renderDbg();
    showToast('Kontakt aktualisiert ✓');
  } else {
    kontakte.push({id:uid(),type:currentKontaktType,qualitaet:currentKontaktQual,...(person?{person}:{})});
    closeModal('fam-m-kontakt');renderSozial();renderDbg();
    showToast(`${TYPE_ICONS[currentKontaktType]} Kontakt erfasst ✓`);
  }
}

function renderSozial(){
  const el=document.getElementById('fam-sozial-list');
  if(!kontakte.length){el.innerHTML='<div style="font-size:11px;color:var(--muted);font-style:italic">Noch keine Kontakte erfasst</div>';return;}
  el.innerHTML=kontakte.map(k=>`
    <div class="sozial-entry" data-kid="${k.id}">
      <div class="se-icon">${TYPE_ICONS[k.type]}</div>
      <div class="se-body">
        <div class="se-type">${k.type.charAt(0).toUpperCase()+k.type.slice(1)}${k.person?' · '+k.person:''}</div>
        <div class="se-meta"><span class="se-qual ${k.qualitaet}">${k.qualitaet}</span></div>
      </div>
      <div style="display:flex;flex-direction:column;align-items:flex-end;gap:4px;flex-shrink:0">
        <button class="se-del" onclick="window.fam_deleteKontakt('${k.id}')">✕</button>
        <span style="font-size:9px;color:var(--muted)">⋯</span>
      </div>
    </div>`).join('');
}

function deleteKontakt(id){kontakte=kontakte.filter(k=>k.id!==id);renderSozial();renderDbg();}

function openModal(id){document.getElementById(id).classList.add('open')}
function closeModal(id){document.getElementById(id).classList.remove('open')}
// modal listeners: global
let tt;function showToast(msg){const el=document.getElementById('toast');el.textContent=msg;el.classList.add('show');clearTimeout(tt);tt=setTimeout(()=>el.classList.remove('show'),2200);}

// Exports
window.fam_lpAction=function(entry){if(typeof openEditKontakt==='function')openEditKontakt(entry.dataset.kid);};
  window.fam_deleteKontakt = deleteKontakt;
  window.fam_saveFamComment = saveFamComment;
  window.fam_openAddKontakt = openAddKontakt;
  window.fam_saveKontakt = saveKontakt;
  window.fam_setFamStimmung = setFamStimmung;
  window.fam_setKontaktQual = setKontaktQual;
  window.fam_setKontaktType = setKontaktType;
  window.fam_toggleAnker = toggleAnker;
  window.fam_toggleFamComment = toggleFamComment;
})();

hyp.js:
(function() {
const STATUS_LABEL = {
  aktiv:       '🔵 Aktiv',
  bestaetigt:  '✅ Bestätigt',
  widerlegt:   '❌ Widerlegt',
  angepasst:   '🔄 Angepasst',
};

function uid(){ return Math.random().toString(36).slice(2,9); }
function nowISO(){ return new Date().toISOString().slice(0,10); }
function formatDate(iso){
  const d=new Date(iso+'T12:00:00');
  const mo=['Jan','Feb','Mär','Apr','Mai','Jun','Jul','Aug','Sep','Okt','Nov','Dez'];
  return `${d.getDate()}. ${mo[d.getMonth()]} ${d.getFullYear()}`;
}

// ── STATE ─────────────────────────────────
// hypothesen: [{id, text, status, erstellt, log:[{datum, status, notiz}]}]
let hypothesen = [
  {
    id: 'h1',
    text: 'Meine Hautentzündungen (Seborrhoische Dermatitis) werden durch eine überschießende Immunreaktion auf Malassezia verursacht — und lassen sich durch Ketoconazol (topisch) sowie systemische Mastzellstabilisierung mit Quercetin messbar reduzieren.',
    status: 'aktiv',
    erstellt: '2026-04-03',
    log: [
      { datum:'2026-04-07', status:'aktiv', notiz:'Terzolin zeigt nach 4 Anwendungen klare Verbesserung. Hals-Region von 4 auf 3. Fortsetzung.' }
    ]
  },
  {
    id: 'h2',
    text: 'Alkoholkonsum (besonders Bier) verschlechtert meine Hautsymptome innerhalb von 12–24 Stunden messbar.',
    status: 'bestaetigt',
    erstellt: '2026-03-15',
    log: [
      { datum:'2026-03-28', status:'bestaetigt', notiz:'Klare Korrelation über 3 Episoden beobachtet. Entzündungswert +1,5 am Folgetag nach Bier.' }
    ]
  },
  {
    id: 'h3',
    text: 'Joghurt ist ein Trigger für meine Darmbeschwerden.',
    status: 'aktiv',
    erstellt: '2026-04-01',
    log: []
  },
];

let updateCtx = null;
let editCtx = null;
let expandedIds = new Set(['h1']); // first one open by default

// ── RENDER ────────────────────────────────
function render(){
  const container = document.getElementById('hyp-list');
  if(!hypothesen.length){
    container.innerHTML=`<div style="font-size:11px;color:var(--muted);font-style:italic;padding:8px 0">
      Noch keine Hypothesen. Formuliere deine erste These!</div>`;
    renderDbg(); return;
  }

  container.innerHTML = hypothesen.map(h=>{
    const isOpen = expandedIds.has(h.id);
    const preview = h.text.slice(0,60)+(h.text.length>60?'…':'');

    const body = isOpen ? `
    <div class="hyp-body">
      <div style="padding-top:12px">
        <div class="hyp-header">
          <span class="hyp-text">"${escHtml(h.text)}"</span>
        </div>

        ${h.log.length ? `
        <div class="hyp-log">
          ${h.log.map(l=>`
            <div class="hyp-log-entry">
              <span class="hyp-log-date">${formatDate(l.datum)}</span>
              <span class="hyp-log-text">${escHtml(l.notiz)}</span>
            </div>`).join('')}
        </div>` : ''}

        <div class="hyp-meta">
          <span class="hyp-date">Erstellt: ${formatDate(h.erstellt)}</span>
          <div class="hyp-actions">
            <button class="btn-sm" onclick="window.hyp_openUpdate('${h.id}')">+ Update</button>
            <button class="btn-sm" onclick="window.hyp_openEdit('${h.id}')">✎</button>
            <button class="btn-sm danger" onclick="window.hyp_deleteHyp('${h.id}')">✕</button>
          </div>
        </div>
      </div>
    </div>` : '';

    return `<div class="hyp-card ${h.status}">
      <div class="hyp-collapsed-header" onclick="window.hyp_toggleHyp('${h.id}')">
        <span class="hyp-chevron${isOpen?' open':''}">▼</span>
        <span class="hyp-preview${isOpen?' expanded':''}">"${escHtml(preview)}"</span>
        <span class="hyp-status-badge badge-${h.status}">${STATUS_LABEL[h.status]}</span>
      </div>
      ${body}
    </div>`;
  }).join('');

}

function escHtml(s){ return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

function toggleHyp(id){
  if(expandedIds.has(id)) expandedIds.delete(id);
  else expandedIds.add(id);
  render();
}

// ── NEW HYPOTHESE ─────────────────────────
function openNewHyp(){
  editCtx = null;
  document.getElementById('hyp-m-new-title').textContent = 'Hypothese formulieren';
  document.getElementById('hyp-m-new-text').value = '';
  document.getElementById('hyp-m-new-status').value = 'aktiv';
  openModal('hyp-m-new');
  setTimeout(()=>document.getElementById('hyp-m-new-text').focus(), 100);
}

function openEdit(id){
  const h = hypothesen.find(x=>x.id===id);
  if(!h) return;
  editCtx = {id};
  document.getElementById('hyp-m-new-title').textContent = 'Hypothese bearbeiten';
  document.getElementById('hyp-m-new-text').value = h.text;
  document.getElementById('hyp-m-new-status').value = h.status;
  openModal('hyp-m-new');
  setTimeout(()=>document.getElementById('hyp-m-new-text').focus(), 100);
}

function saveHyp(){
  const text = document.getElementById('hyp-m-new-text').value.trim();
  const status = document.getElementById('hyp-m-new-status').value;
  if(!text){ showToast('Bitte These eingeben'); return; }

  if(editCtx){
    const h = hypothesen.find(x=>x.id===editCtx.id);
    if(h){ h.text=text; h.status=status; }
    showToast('Hypothese aktualisiert ✓');
  } else {
    const newId = uid();
    hypothesen.unshift({ id:newId, text, status, erstellt:nowISO(), log:[] });
    expandedIds.add(newId);
    showToast('Hypothese gespeichert ✓');
  }
  editCtx = null;
  closeModal('hyp-m-new');
  render();
}

function deleteHyp(id){
  hypothesen = hypothesen.filter(x=>x.id!==id);
  render();
  showToast('Hypothese entfernt');
}

// ── UPDATE ────────────────────────────────
function openUpdate(id){
  const h = hypothesen.find(x=>x.id===id);
  if(!h) return;
  updateCtx = {id};
  document.getElementById('hyp-m-update-sub').textContent =
    `"${h.text.slice(0,60)}${h.text.length>60?'…':''}"`;
  document.getElementById('hyp-m-update-status').value = h.status;
  document.getElementById('hyp-m-update-text').value = '';
  openModal('hyp-m-update');
  setTimeout(()=>document.getElementById('hyp-m-update-text').focus(), 100);
}

function confirmUpdate(){
  if(!updateCtx) return;
  const h = hypothesen.find(x=>x.id===updateCtx.id);
  if(!h) return;
  const status = document.getElementById('hyp-m-update-status').value;
  const notiz  = document.getElementById('hyp-m-update-text').value.trim();
  if(!notiz){ showToast('Bitte Erkenntnis eingeben'); return; }
  h.status = status;
  h.log.push({ datum:nowISO(), status, notiz });
  updateCtx = null;
  closeModal('hyp-m-update');
  render();
  showToast('Update gespeichert ✓');
}

// ── MODALS ────────────────────────────────
function openModal(id){ document.getElementById(id).classList.add('open'); }
function closeModal(id){ document.getElementById(id).classList.remove('open'); }

// ── TOAST ─────────────────────────────────
let tt;
function showToast(msg){
  const el=document.getElementById('toast');
  el.textContent=msg; el.classList.add('show');
  clearTimeout(tt); tt=setTimeout(()=>el.classList.remove('show'), 2200);
}
// Exports
  window.hyp_deleteHyp = deleteHyp;
  window.hyp_openEdit = openEdit;
  window.hyp_openUpdate = openUpdate;
  window.hyp_toggleHyp = toggleHyp;
  window.hyp_confirmUpdate = confirmUpdate;
  window.hyp_openNewHyp = openNewHyp;
  window.hyp_render = render;
  window.hyp_saveHyp = saveHyp;
  window.hyp_render = render;
})();
